INSERT INTO detections (
  rule_id, name, description, severity, platform,
  mitre_attack_id, mitre_tactic, mitre_technique,
  nist_controls, data_sources, query, query_language, tags,
  expected_alerts_per_day, expected_fp_rate, expected_mttd_hours,
  is_global, tenant_id, log_sources, device_types
) VALUES
('DET-0101', 'Unauthorized Connection Through Firewall', 'Any communication through the firewall not explicitly granted by policy could indicate either a misconfiguration or even malicious actions, putting your security and compliance at risk.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0102', 'AWS Cloud Provisioning Activity from Unusual IP', 'Looks for AWS Provisioning activities that occur from new IPs (for organizations with strict IP controls).', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0103', 'Host With A Recurring Malware Infection', 'Alerts when a host has an infection that has been re-infected remove multiple times over multiple days.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1204', 'Execution', 'User Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0104', 'AWS Cloud Provisioning Activity from Unusual Country', 'Looks for AWS Provisioning activities that occur from new IPs, using GeoIP to resolve the Country.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0105', 'User Login to Unauthorized Geo', 'For regulated environments, detect users logging into servers where they''re not permitted.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Audit Trail","AWS"}', '{"Identity Provider","Active Directory","Audit System","AWS Cloud"}'),
('DET-0106', 'Find Processes with Renamed Executables', 'Oftentimes, attackers will execute a temporary file, and rename it to something innocuous (e.g. svchost.exe) to maintain persistence. This search will look for renamed executables. (https://car.mitre.org/wiki/CAR-2013-05-009">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0107', 'Reg.exe used to hide files/directories via registry keys', 'The search looks for command-line arguments used to hide a file or directory using the reg add command.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1060', 'Defense Evasion', 'Registry Run Keys / Startup Folder', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = reg.exe Processes.process="*add*" Processes.process="*Hidden*" Processes.process="*REG_DWORD*" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user| `drop_dm_object_name(Processes)` | `ctime(firstTime)` |`ctime(lastTime)`| regex process = "(/d\s+2)"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0108', 'Emails from Outside the Organization with Company Domains', 'Phishers will often try to send emails where the from address uses your organization''s domain name, e.g., emailing finance from yourceo@yourcompany.com. Detect that now!Alert Volume: Very Low', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1192', 'Initial Access', 'Spearphishing Link', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0109', 'Detect hosts connecting to dynamic domain providers', 'Malicious actors often abuse legitimate Dynamic DNS services to host malicious payloads or interactive command and control nodes. Attackers will automate domain resolution changes by routing dynamic domains to countless IP addresses to circumvent firewall blocks, blacklists as well as frustrate a network defenders analytic and investigative processes. This search will look for DNS queries made from within your infrastructure to suspicious dynamic domains.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Defense Evasion', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count values(DNS.answer) as answer min(_time) as firstTime from datamodel=Network_Resolution by DNS.src, DNS.query | `drop_dm_object_name("DNS")` | `ctime(firstTime)` | `dynamic_dns_providers`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0110', 'Detect Use of cmd.exe to Launch Script Interpreters', 'This search looks for the execution of the cscript.exe or wscript.exe processes, with a parent of cmd.exe. The search will return the count, the first and last time this execution was seen on a machine, the user, and the destination of the machine', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.parent_process="*cmd.exe" (Processes.process_name=cscript.exe OR Processes.process_name =wscript.exe) by Processes.parent_process Processes.process_name Processes.user Processes.dest | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0111', 'Hiding Files And Directories With Attrib.exe', 'Attackers leverage an existing Windows binary, attrib.exe, to mark specific as hidden by using specific flags so that the victim does not see the file.  The search looks for specific command-line arguments to detect the use of attrib.exe to hide files.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1158', 'Defense Evasion', 'Hidden Files and Directories', '{}', '{}', '| tstats `summariesonly` count min(_time) values(Processes.process) as process max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=attrib.exe (Processes.process=*+h*) by Processes.parent_process Processes.process_name Processes.user | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0112', 'Detection of tools built by NirSoft', 'This search looks for specific command-line arguments that may indicate the execution of tools made by Nirsoft, which are legitimate, but may be abused by attackers.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1087', 'Execution', 'Account Discovery', '{}', '{}', '| tstats `summariesonly` count min(_time) values(Processes.process) as process max(_time) as lastTime from datamodel=Endpoint.Processes where (Processes.process="* /stext *" OR Processes.process="* /scomma *" ) by Processes.parent_process Processes.process_name Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` |`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0113', 'Monitor AutoRun Registry Keys', 'Attackers often add malware to the https://msdn.microsoft.com/en-us/library/windows/desktop/aa376977(v=vs.85).aspx">Windows Autorun registry keys to maintain persistence. This search looks through registry data for suspicious activities.Alert Volume: High', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1060', 'Persistence', 'Registry Run Keys / Startup Folder', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0114', 'First Time Seen Running Windows Service', 'This search looks for the first time a Windows service is seen running in your environment.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1050', 'Execution', 'New Service', '{}', '{}', 'eventtype=wineventlog_system signature_id=7036 | rex field=Message "The (?<serviceName>[\w\s-]*) service entered the (?<action>\w*) state" | where action="running" | inputlookup append=t previously_seen_running_windows_services | multireport [| stats earliest(eval(coalesce(_time, firstTime))) as firstTime, latest(eval(coalesce(_time, lastTime))) as lastTime by serviceName | outputlookup previously_seen_running_windows_services | where fact=fiction] [| eventstats earliest(eval(coalesce(_time, firstTime))) as firstTime, latest(eval(coalesce(_time, lastTime))) as lastTime by serviceName | where firstTime >= relative_time(now(), "-60m@m") AND isnotnull(_time) | stats values(dest) as dest by _time, serviceName] | table _time, serviceName, dest', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0115', 'Detect Unauthorized Assets by MAC address', 'By populating the organization''s assets within the assets_by_str.csv, we will be able to detect unauthorized devices that are trying to connect with the organization''s network by inspecting DHCP request packets, which are issued by devices when they attempt to obtain an IP address from the DHCP server. The MAC address associated with the source of the DHCP request is checked against the list of known devices, and reports on those that are not found.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1200', 'Initial Access', 'Hardware Additions', '{}', '{}', '| tstats `summariesonly` count from datamodel=Network_Sessions where nodename=All_Sessions.DHCP All_Sessions.signature=DHCPREQUEST by All_Sessions.src_ip All_Sessions.src_mac | dedup All_Sessions.src_mac| `drop_dm_object_name("Network_Sessions")`|`drop_dm_object_name("All_Sessions")` | search NOT [| inputlookup asset_lookup_by_str |rename mac as src_mac | fields + src_mac]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"IP Address Assignment"}', '{}'),
('DET-0116', 'Batch File Write to System32', 'The search looks for a batch file (.bat) written to the Windows system directory tree.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1064', 'Execution', 'Scripting', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.dest) as dest values(Filesystem.file_name) as file_name values(Filesystem.user) as user from datamodel=Endpoint.Filesystem by Filesystem.file_path | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`| rex field=file_name "(?<file_extension>\.[^\.]+)$" | search file_path=*system32* AND file_extension=.bat', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0117', 'Shim Database File Creation', 'This search looks for shim database files being written to default directories. The sdbinst.exe application is used to install shim database files (.sdb). According to Microsoft, a shim is a small library that transparently intercepts an API, changes the parameters passed, handles the operation itself, or redirects the operation elsewhere.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1138', 'Persistence', 'Application Shimming', '{}', '{}', '| tstats `summariesonly` count values(Filesystem.action) values(Filesystem.file_hash) as file_hash values(Filesystem.file_path) as file_path  min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Filesystem where Filesystem.file_path=*Windows\AppPatch\Custom* by Filesystem.file_name Filesystem.dest | `ctime(lastTime)` | `ctime(firstTime)` |`drop_dm_object_name(Filesystem)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0118', 'Basic TOR Traffic Detection', 'The anonymity of TOR makes it the perfect place to hide C&C, exfiltration, or ransomware payment via bitcoin. This example looks for ransomware activity based on FW logs.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0119', 'Multiple Infections on Host', 'Finds hosts that have logged multiple different infections in a short period of time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0120', 'Email Attachments With Lots Of Spaces', 'Attackers often use spaces as a means to obfuscate an attachment''s file extension. This search looks for messages with email attachments that have many spaces within the filename.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1193', 'Initial Access', 'Spearphishing Attachment', '{}', '{}', '| tstats `summariesonly` count values(All_Email.recipient) as recipient_address min(_time) as firstTime max(_time) as lastTime from datamodel=Email where All_Email.file_name="*" by All_Email.src_user, All_Email.file_name All_Email.message_id | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name("All_Email")` | eval space_ratio = (mvcount(split(file_name," "))-1)/len(file_name) | search space_ratio >= 0.1 |  rex field=recipient_address "(?<recipient_user>.*)@"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0121', 'RFC1918 IP Not in CMDB', 'Find internal addresses that aren''t in your Asset database.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1200', 'Initial Access', 'Hardware Additions', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0122', 'Schtasks used for forcing a reboot', 'This search looks for flags passed to schtasks.exe on the command-line that indicate that a forced reboot of system is scheduled.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1053', 'Persistence', 'Scheduled Task', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = schtasks.exe Processes.process="*shutdown*" Processes.process="*/r*" Processes.process="*/f*" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0123', 'Malicious PowerShell Process - Connect To Internet With Hidden Window', 'This search looks for PowerShell processes started with parameters to modify the execution policy of the run, run in a hidden window, and connect to the Internet. This combination of command-line options is suspicious because it''s overriding the default PowerShell execution policy, attempts to hide its activity from the user, and connects to the Internet.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=powershell.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search process="*-Exec*" process="*-WindowStyle*" process="*hidden*" process="*New-Object*" process="*System.Net.WebClient*"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0124', 'SIEM-P-None-XX-AWS Network Access Control List Created with All Open Ports', 'The search looks for CloudTrail events to detect if any network ACLs were created with all the ports open to a specified CIDR.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Persistence', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventName=CreateNetworkAclEntry | mvexpand requestParameters | mvexpand responseElements | search requestParameters.portRange.from=1024 requestParameters.portRange.to=65525 requestParameters.ruleAction=allow | rename userIdentity.arn as arn | rename requestParameters.networkAclId as networkAclId | table _time aws_account_id src userName arn networkAclId requestParameters.* responseElements.*', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0125', 'DNS record changed', 'The search takes the DNS records and their answers results of the discovered_dns_records lookup and finds if any records have changed by searching DNS response from the Network_Resolution datamodel across the last day.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Exfiltration', 'Commonly Used Port', '{}', '{}', '| inputlookup discovered_dns_records.csv | rename answer as discovered_answer | join domain[|tstats summariesonly=true count values(DNS.record_type) as type, values(DNS.answer) as current_answer values(DNS.src) as src from datamodel=Network_Resolution where DNS.message_type=RESPONSE DNS.answer!="unknown" DNS.answer!="" by DNS.query | rename DNS.query as query | where query!="unknown" | rex field=query "(?<domain>\w+\.\w+?)(?:$|/)"] | makemv delim=" " answer |  makemv delim=" " type | sort -count | table count,src,domain,type,query,current_answer,discovered_answer | makemv current_answer  | mvexpand current_answer | makemv discovered_answer | eval n=mvfind(discovered_answer, current_answer) | where isnull(n)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0126', 'Attempted Credential Dump From Registry Via Reg.exe', 'This search looks for execution of reg.exe with parameters specifying an export of keys that contain hashed credentials that attackers may try to crack offline,', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1003', 'Credential Access', 'Credential Dumping', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=reg.exe  by Processes.user Processes.process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search process=*save* (process=*HKLM\\sam* OR process=*HKLM\\system*)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0127', 'First Time Accessing an Internal Git Repository', 'Find users who accessed a git repository for the first time.Alert Volume: High', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0128', 'Excessive DNS Failures', 'This search identifies DNS query failures by counting the number of DNS responses that do not indicate success, and trigger on more than 50 occurrences.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '| tstats `summariesonly` count values("DNS.query") as queries from datamodel=Network_Resolution where nodename=DNS "DNS.reply_code"!="No Error" "DNS.reply_code"!="NoError" DNS.reply_code!="unknown" NOT "DNS.query"="*.arpa" "DNS.query"="*.*" by "DNS.src","DNS.query"| `drop_dm_object_name("DNS")`| lookup cim_corporate_web_domain_lookup domain as query OUTPUT domain| where isnull(domain)| lookup update=true alexa_lookup_by_str domain as query OUTPUT rank| where isnull(rank)| stats sum(count) as count mode(queries) as queries by src| `get_asset(src)`| where count>50', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0129', 'New Suspicious cmd.exe / regedit.exe / powershell.exe Service Launch', 'Very rarely would cmd.exe, regedit.exe, or powershell.exe be launched by services.exe. This search will detect that malware persistence strategy. ("https://car.mitre.org/wiki/CAR-2014-05-002">MITRE CAR Reference)Alert Volume: Very Low (for most companies)', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1050', 'Privilege Escalation', 'New Service', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0130', 'AWS Unusual Amount of Modifications to ACLs', 'Looks for a large number of Security Group ACL changes in a short period of time for a user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0131', 'New Local Admin Account', 'Local admin accounts are used by legitimate technicians, but they''re also used by attackers. This search looks for newly created accounts that are elevated to local admins.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Defense Evasion', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0132', 'Suspicious writes to windows Recycle Bin', 'This search detects writes to the recycle bin by a process other than explorer.exe.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1074', 'Collection', 'Data Staged', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.file_path) as file_path values(Filesystem.file_name) as file_name FROM datamodel=Endpoint.Filesystem where Filesystem.filepath = "*$Recycle.Bin*" by Filesystem.process_id Filesystem.dest | `drop_dm_object_name("Filesystem")`| search [| tstats `summariesonly` values(Processes.user) as user values(Processes.process_name) as process_name values(Processes.parent_process_name) as parent_process_name FROM datamodel=Endpoint.Processes where Processes.process_name != "explorer.exe" by Processes.process_id Processes.dest| `drop_dm_object_name("Processes")` | table process_id dest]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0133', 'Overwriting Accessibility Binaries', 'Microsoft Windows contains accessibility features that can be launched with a key combination before a user has logged in. An adversary can modify or replace these programs so they can get a command prompt or backdoor without logging in to the system. This search looks for modifications to these binaries.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1015', 'Persistence', 'Accessibility Features', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.user) as user values(Filesystem.dest) as dest values(Filesystem.file_path) as file_path from datamodel=Endpoint.Filesystem where (Filesystem.file_path=*\Windows\System32\sethc.exe* OR Filesystem.file_path=*\Windows\System32\utilman.exe* OR Filesystem.file_path=*\Windows\System32\osk.exe* OR Filesystem.file_path=*\Windows\System32\Magnify.exe* OR Filesystem.file_path=*\Windows\System32\Narrator.exe* OR Filesystem.file_path=*\Windows\System32\DisplaySwitch.exe* OR Filesystem.file_path=*\Windows\System32\AtBroker.exe*) by Filesystem.file_name Filesystem.dest | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0134', 'Stale Account Usage', 'Detect long-inactive accounts that suddenly become active.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0135', 'Multiple Authentication Failures', 'Detects outliers in the timeseries of service or machine authentication failures per user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0136', 'Web Fraud - Account Harvesting', 'This search is used to identify the creation of multiple user accounts using the same email domain name.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1136', 'None', 'Create Account', '{}', '{}', 'sourcetype=stream:http http_content_type=text* uri="/magento2/customer/account/loginPost/" | rex field=cookie "form_key=(?<SessionID>\w+)" | rex field=form_data "login\[username\]=(?<Username>[^&|^$]+)" | search Username=* | rex field=Username "@(?<email_domain>.*)"|stats dc(Username) as UniqueUsernames list(Username) as src_user by email_domain|where UniqueUsernames> 25', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0137', 'SIEM-E-None-XX-Flight Risk Web Browsing', 'This search implements several heuristics to look for indications that a user is a flight risk from Web Logs. Detect a user who may be leaving before they do.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Exfiltration', 'None', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0138', 'Suspicious Changes to File Associations', 'This search looks for changes to registry values that control Windows file associations, executed by a process that is not typical for legitimate, routine changes to this area.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1042', 'Persistence', 'Change Default File Association', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Processes.process_name) as process_name values(Processes.parent_process_name) as parent_process_name FROM datamodel=Endpoint.Processes where Processes.process_name!=Explorer.exe AND Processes.process_name!=OpenWith.exe by Processes.process_id Processes.dest | `drop_dm_object_name("Processes")` | `ctime(firstTime)` | `ctime(lastTime)` | join [| tstats `summariesonly` values(Registry.registry_path) as registry_path count  FROM datamodel=Endpoint.Registry where Registry.registry_path=*\\Explorer\\FileExts* by Registry.process_id Registry.dest | `drop_dm_object_name("Registry")` | table process_id dest registry_path]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0139', 'Detect Activity Related to Pass the Hash Attacks', 'This search looks for specific authentication events from the Windows Security Event logs to detect potential attempts at using the Pass-the-Hash technique.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1075', 'Lateral Movement', 'Pass the Hash', '{}', '{}', 'eventtype=wineventlog_security (signature_id = 4624 OR signature_id = 4625) Logon_Process = NtLmSsp Logon_Type=3 Account_Name ! = "ANONYMOUS LOGON" Key_Length = 0 | table _time src_ip user dest dest_nt_domain signature_id signature', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0140', 'New Tables Queried by Salesforce.com User', 'Salesforce.com supports a simplified query language called SOQL. This search detects users who begin querying new sensitive tables.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Discovery', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0141', 'Web Fraud - Anomalous User Clickspeed', 'This search is used to examine web sessions to identify those where the clicks are occurring too quickly for a human or are occurring with a near-perfect cadence (high periodicity or low standard deviation), resembling a script driven session.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Execution', 'Valid Accounts', '{}', '{}', 'sourcetype=stream:http http_content_type=text* | rex field=cookie "form_key=(?<session_id>\w+)" | streamstats window=2 current=1 range(_time) as TimeDelta by session_id | where TimeDelta>0 |stats count stdev(TimeDelta) as ClickSpeedStdDev avg(TimeDelta) as ClickSpeedAvg by session_id | where count>5 AND (ClickSpeedStdDev<.5 OR ClickSpeedAvg<.5)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0142', 'Processes launching netsh', 'This search looks for processes launching netsh.exe. Netsh is a command-line scripting utility that allows you to, either locally or remotely, display or modify the network configuration of a computer that is currently running. Netsh can be used as a persistence proxy technique to execute a helper DLL when netsh.exe is executed. In this search, we are looking for processes spawned by netsh.exe and executing commands via the command line.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process=netsh.exe by Processes.parent_process Processes.process_name Processes.user Processes.dest | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0143', 'WMI Permanent Event Subscription', 'This search looks for the creation of WMI permanent event subscriptions.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', 'sourcetype="wineventlog:microsoft-windows-wmi-activity/operational" EventCode=5861 Binding | rex field=Message "Consumer =\s+(?<consumer>[^;|^$]+)" | search consumer!="NTEventLogEventConsumer=\"SCM Event Log Consumer\"" | stats count min(_time) as firstTime max(_time) as lastTime by ComputerName, consumer, Message | `ctime(firstTime)`| `ctime(lastTime)` | rename ComputerName as dest', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0144', 'SIEM-CC-T1071.004-Excessive DNS Failures', 'Alerts when a host receives many DNS failures in a short span', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1071.004', 'Command and Control', 'Standard Application Layer Protocol', '{}', '{}', '| tstats `summariesonly` count values("DNS.query") as queries from datamodel=Network_Resolution where nodename=DNS "DNS.reply_code"!="No Error" "DNS.reply_code"!="NoError" DNS.reply_code!="unknown" NOT "DNS.query"="*.arpa" "DNS.query"="*.*" by "DNS.src","DNS.query"| `drop_dm_object_name("DNS")`| lookup cim_corporate_web_domain_lookup domain as query OUTPUT domain| where isnull(domain)| lookup update=true alexa_lookup_by_str domain as query OUTPUT rank| where isnull(rank)| stats sum(count) as count mode(queries) as queries by src| `get_asset(src)`| where count>50', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0145', 'Anomalous New Listening Port', 'Alerts a series of hosts begin listening on a new port within 24 hours. This may be an indication that the devices have been compromised or have had new (and potentially vulnerable) software installed.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1065', 'Command and Control', 'Uncommonly Used Port', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0146', 'High Volume of Traffic from High or Critical Host Observed', 'Alerts when a host of high or critical severity generates a high volume of outbound traffic. This may indicate that the host has been compromised.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0147', 'Prohibited Network Traffic Allowed', 'This search looks for network traffic defined by port and transport layer protocol in the Enterprise Security lookup table "lookup_interesting_ports", that is marked as prohibited, and has an associated ''allow'' action in the Network_Traffic data model. This could be indicative of a misconfigured network device.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Command and Control', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Network_Traffic where All_Traffic.action = allowed by All_Traffic.src_ip All_Traffic.dest_ip All_Traffic.dest_port All_Traffic.action | lookup update=true interesting_ports_lookup dest_port as All_Traffic.dest_port OUTPUT app is_prohibited note transport | search is_prohibited=true | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name("All_Traffic")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0148', 'SIEM-CA-None-XX-Detect new user AWS Console Login', 'This search looks for CloudTrail events wherein a console login event by a user was recorded within the last hour, then compares the event to a lookup file of previously seen users (by ARN values) who have logged into the console. The alert is fired if the user has logged into the console for the first time within the last hour', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Credential Access', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventName=ConsoleLogin | rename userIdentity.arn as user  |stats earliest(_time) as earliest latest(_time) as latest by user | inputlookup append=t previously_seen_users_console_logins.csv  | stats min(earliest) as earliest max(latest) as latest by user | eval userStatus=if(earliest >= relative_time(now(), "-70m@m"), "First Time Logging into AWS Console","Previously Seen User") | convert ctime(earliest) ctime(latest) | where userStatus ="First Time Logging into AWS Console"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0149', 'Attempt To Stop Security Service', 'This search looks for attempts to stop security-related services on the endpoint.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where (Processes.process_name = net.exe OR  Processes.process_name = sc.exe) Processes.process="* stop *" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)` |lookup security_services_lookup service as process OUTPUTNEW category, description | search category=security', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0150', 'Remote Process Instantiation via WMI', 'This search looks for wmic.exe being launched with parameters to spawn a process on a remote system.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = wmic.exe Processes.process="*/node*" Processes.process="*process*" Processes.process="*call*" Processes.process="*create*"   by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` |`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0151', 'Many USB File Copies for User', 'Build a baseline of how many file copies each user does to USB media, and detect when a user copies an uncharacteristically large number of files.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP","Endpoint Detection and Response"}', '{"Data Loss Prevention","EDR","Endpoint"}'),
('DET-0152', 'Basic Malware Outbreak', 'Looks for the same malware occurring on multiple systems in a short period of time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0153', 'Create or delete hidden shares using net.exe', 'This search looks for the creation or deletion of hidden shares using net.exe.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.user) as user values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where (Processs.process_name=net.exe OR Processes.process_name=net1.exe) by Processes.process Processes.process_name Processes.dest | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search (process=*share* OR process=*delete*)| regex process="\S+[$]"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0154', 'Unusually Long VPN Session', 'Detects unusually long VPN sessions, based on a user''s baseline and their peer group.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"IP Address Assignment"}', '{}'),
('DET-0155', 'Short Lived Admin Accounts', 'A technique used by attackers is to create an account, take some actions, and then delete it right away. This search will find those accounts on the local system.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1136', 'Defense Evasion', 'Create Account', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0156', 'Processes with Lookalike (typo) Filenames', 'To evade analysts, attackers will create a service with a name similar to that of a standard Windows service. This search looks for small differences. Idea from David Bianco, formerly of Sqrrl (http://detect-respond.blogspot.com/2016/11/hunting-for-malware-critical-process.html">link).Alert Volume: Very Low', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0157', 'New User Taking Privileged Actions', 'Record when a user who hasn''t taken privileged actions before suddenly starts.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0158', 'Remote WMI Command Attempt', 'This search looks for wmic.exe being launched with parameters to operate on remote systems.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=wmic.exe  AND Processes.process= */node* by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0159', 'Attempt To Add Certificate To Untrusted Store', 'Attempt to add a certificate to the untrusted certificate store', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '| tstats `summariesonly` count min(_time) values(Processes.process) as process max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=certutil.exe (Processes.process=*-addstore* AND Processes.process=*disallowed* ) by Processes.parent_process Processes.process_name Processes.user | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0160', 'Blacklisted IP Address', 'Generates anomalies for traffic that goes to Blacklisted IPs', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1094', 'Command and Control', 'Custom Command and Control Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0161', 'New Logon Type for User', 'Windows defines several logon types (Interactive, RemoteInteractive, Network, etc.). Established users rarely generate new logon types. This search will look for that scenario. (https://car.mitre.org/wiki/CAR-2013-02-012">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0162', 'AWS New API Call Per User', 'Looks for users that are using AWS APIs that they''ve never used before.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1260', 'Execution', 'Determine 3rd party infrastructure services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0163', 'Multiple Outgoing Connections', 'Multiple Outgoing Connections', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0164', 'Geographically Improbable Access Detected against Category', 'To ensure you have a GDPR-mandated audit trail with individual accounts for each person, detect when the same account is logged into twice in a short period of time but from locations very far away, to a GDPR-tagged system.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Audit Trail","Audit Trail","AWS"}', '{"Identity Provider","Active Directory","Audit System","AWS Cloud"}'),
('DET-0165', 'In-Scope System with Windows Update Disabled', 'Any GDPR-tagged systems not receiving updates could jeopardize your GDPR status due to Article 32. Detect systems where the Windows Update service is disabled.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Patch Management"}', '{}'),
('DET-0166', 'Child Processes of Spoolsv.exe', 'This search looks for child processes of spoolsv.exe. This activity is associated with a POC privilege-escalation exploit associated with CVE-2018-8440. Spoolsv.exe is the process associated with the Print Spooler service in Windows and typically runs as SYSTEM.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1068', 'Privilege Escalation', 'Exploitation for Privilege Escalation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process_name) as process_name values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.parent_process_name=spoolsv.exe AND Processes.process_name!=regsvr32.exe by Processes.dest Processes.parent_process Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0167', 'High Or Critical Priority Host With Malware Detected', 'Alerts when an infection is noted on a host with high or critical priority.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0168', 'Registry Keys for Creating SHIM Databases', 'This search looks for registry activity associated with application compatibility shims, which can be leveraged by attackers for various nefarious purposes.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1138', 'Persistence', 'Application Shimming', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Change_Analysis.All_Changes where All_Changes.object_category=registry AND (All_Changes.object_path="*CurrentVersion\\AppCompatFlags\\Custom*" OR All_Changes.object_path="*CurrentVersion\\AppCompatFlags\\InstalledSDB*") by All_Changes.dest, All_Changes.command, All_Changes.user, All_Changes.object, All_Changes.object_path | `drop_dm_object_name("All_Changes")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0169', 'SIEM-E-TA000-XX-File with Samsam Extension', 'The search looks for file writes with extensions consistent with a SamSam ransomware attack.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'Execution', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.user) as user values(Filesystem.dest) as dest values(Filesystem.file_path) as file_path from datamodel=Endpoint.Filesystem by Filesystem.file_name | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`| rex field=file_name "(?<file_extension>\.[^\.]+)$" | search file_extension=.stubbin OR file_extension=.berkshire OR file_extension=.satoshi OR file_extension=.sophos OR file_extension=.keyxml', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0170', 'Windows Event Log Clearing Events', 'This use case looks for Windows event codes that indicate the Windows Audit Logs were tampered with.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0171', 'Uncommon Processes On Endpoint', 'This search looks for applications on the endpoint that you have marked as prohibited.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1015', 'Execution', 'Accessibility Features', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes by Processes.dest Processes.user Processes.process Processes.process_name | `ctime(firstTime)`| `ctime(lastTime)` | `drop_dm_object_name(Processes)` | `uncommon_processes`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0172', 'Spike in Downloaded Documents Per User from Salesforce.com', 'Salesforce.com contains the most critical information for many companies. This example tracks the number of documents downloaded per day per user, to detect exfiltration.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0173', 'Increase in Pages Printed', 'Find users who printed more pages than normal.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit"}', '{}'),
('DET-0174', 'SIEM-LM-TA000-XX-Significant Increase in Interactive Logons', 'Typically non-admin users will only interactively log into one system per day. A user who starts loggin into many can indicate account compromise and lateral movement. (https://car.mitre.org/wiki/CAR-2013-02-012">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Lateral Movement', 'Lateral Movement', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0175', 'Abnormally High Number of HTTP Method Events By Src', 'Alerts when a host has an abnormally high number of HTTP requests by http method.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1190', 'Initial Access', 'Exploit Public-Facing Application', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0176', 'Unrouteable Activity Detected', 'Alerts when activity to or from a host that is unrouteable is detected.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1046', 'Discovery', 'Network Service Scanning', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0177', 'New Application Accessing Salesforce.com API', 'Salesforce.com contains the most critical information for many companies. This search looks for users who connect to SFDC''s reporting API with new clients. Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0178', 'Detect Log Clearing With wevtutil', 'This use case looks for the wevutil process clearing the Windows Audit LogsAlert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0179', 'USN Journal Deletion', 'The fsutil.exe application is a legitimate Windows utility used to perform tasks related to the file allocation table (FAT) and NTFS file systems. The update sequence number (USN) change journal provides a log of all changes made to the files on the disk. This search looks for fsutil.exe deleting the USN journal.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=fsutil.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search process="*deletejournal*" AND process="*usn*"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0180', 'WMI Temporary Event Subscription', 'This search looks for the creation of WMI temporary event subscriptions.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', 'sourcetype="wineventlog:microsoft-windows-wmi-activity/operational" EventCode=5860 Temporary | rex field=Message "NotificationQuery =\s+(?<query>[^;|^$]+)" | search query!="SELECT * FROM Win32_ProcessStartTrace WHERE ProcessName = ''wsmprovhost.exe''" AND query!="SELECT * FROM __InstanceOperationEvent WHERE TargetInstance ISA ''AntiVirusProduct'' OR TargetInstance ISA ''FirewallProduct'' OR TargetInstance ISA ''AntiSpywareProduct''" | stats count min(_time) as firstTime max(_time) as lastTime by ComputerName, query  | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0181', 'Detect Excessive Account Lockouts From Endpoint', 'This search identifies endpoints that have caused a relatively high number of account lockouts in a short period.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Credential Access', 'Valid Accounts', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Change.All_Changes where nodename=All_Changes.Account_Management All_Changes.result="lockout" by All_Changes.dest All_Changes.result |`drop_dm_object_name("All_Changes")` |`drop_dm_object_name("Account_Management")`| `ctime(firstTime)` | `ctime(lastTime)` | search count > 5', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0182', 'Suspicious HTTP redirects', 'Detects sequences of HTTP requests within a short period of time that suggests infection has taken place.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1185', 'Collection', 'Man in the Browser', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0183', 'Healthcare Worker Opening More Patient Records Than Usual', 'If a healthcare worker views more patient records than normal or more than their peers, it could be a sign that their system is infected, or that they are exfiltrating patient data.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0184', 'Detect USB device insertion', 'The search is used to detect hosts that generate Windows Event ID 4663 for successful attempts to write to or read from a removable storage and Event ID 4656 for failures, which occurs when a USB drive is plugged in. In this scenario we are querying the Change_Analysis data model to look for Windows Event ID 4656 or 4663 where the priority of the affected host is marked as high in the ES Assets and Identity Framework.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '| tstats `summariesonly` count earliest(_time) AS earliest latest(_time) AS latest from datamodel=Change_Analysis where (nodename = All_Changes) All_Changes.result="Removable Storage device" (All_Changes.result_id=4663 OR All_Changes.result_id=4656) (All_Changes.src_priority=high) by All_Changes.dest | `drop_dm_object_name("All_Changes")`| `ctime(earliest)`| `ctime(latest)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","DLP"}', '{"EDR","Endpoint","Data Loss Prevention"}'),
('DET-0185', 'Detect Many Unauthorized Access Attempts', 'Most login failures are due to failed passwords. Login failure to sensitive systems where the users simply aren''t authorized, though, can indicate malicious intent. Detect that.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0186', 'Suspicious Email Attachment Extensions', 'This search looks for emails that have attachments with suspicious file extensions.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1193', 'Initial Access', 'Spearphishing Attachment', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Email where All_Email.file_name="*" by All_Email.src_user, All_Email.file_name All_Email.message_id | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name("All_Email")` | `suspicious_email_attachments`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email","Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0187', 'Web Browsing to Unauthorized Sites', 'Detect users who are persistently attempting to violate your proxy policy.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0188', 'Multiple Box Login Errors', 'Detects outliers in the timeseries of Box login failures per Box user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0189', 'Old Passwords in Use', 'Detect active accounts with passwords that haven''t been updated in more than 120 days.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0190', 'User Login with Local Credentials', 'Categorically, most interactive logins should use domain credentials. Detect when a new user logs on with local credentials that bypass most centralized logging and policy systems, but not Splunk!', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0191', 'Suspicious Reg.exe Process', 'This search looks for reg.exe being launched from a command prompt not started by the user. When a user launches cmd.exe, the parent process is usually explorer.exe. This search filters out those instances.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1112', 'Defense Evasion', 'Modify Registry', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Processes where Processes.parent_process_name != explorer.exe Processes.process_name =cmd.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest Processes.process_id Processes.parent_process_id | `drop_dm_object_name("Processes")` | `ctime(firstTime)` | `ctime(lastTime)` | search [| tstats `summariesonly` count FROM datamodel=Endpoint.Processes where Processes.parent_process_name=cmd.exe Processes.process_name= reg.exe by Processes.parent_process_id Processes.dest Processes.process_name | `drop_dm_object_name("Processes")` | `ctime(firstTime)` | `ctime(lastTime)` | rename parent_process_id as process_id |dedup process_id| table process_id dest]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0192', 'Large Web Upload', 'Uses a basic threshold to detect a large web upload, which could be exfiltration from malware or a malicious insider.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0193', 'First Time Logon to New Server', 'Find users who logged into a new server for the first time.Alert Volume: Very High', 'CRITICAL'::detection_severity, 'SPLUNK'::detection_platform, 'T1021', 'Lateral Movement', 'Remote Services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0194', 'Malicious AD Activity', 'Raises anomalies when the input data matches a set of predefined patterns in Microsoft Windows logs.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0195', 'Network Device Rebooted', 'Increases the risk score of network devices that have been rebooted.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Configuration Management"}', '{}'),
('DET-0196', 'Unusually Long Content-Type Length', 'This search looks for unusually long strings in the Content-Type http header that the client sends the server.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1320', 'Defense Evasion', 'Data Hiding', '{}', '{}', 'sourcetype=stream:http | eval cs_content_type_length = len(cs_content_type) | where cs_content_type_length > 100 | table endtime src_ip dest_ip cs_content_type_length cs_content_type url', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0197', 'Detect PsExec With accepteula Flag', 'This search looks for events where <code>PsExec.exe</code> is run with the <code>accepteula</code> flag in the command line. PsExec is a built-in Windows utility that enables you to execute processes on other systems. It is fully interactive for console applications. This tool is widely used for launching interactive command prompts on remote systems. Threat actors leverage this extensively for executing code on compromised systems. If an attacker is running PsExec for the first time, they will be prompted to accept the end-user license agreement (EULA), which can be passed as the argument <code>accepteula</code> within the command line.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = PsExec.exe Processes.process = "*accepteula*" by Processes.process_name Processes.dest  Processes.parent_process_name | `drop_dm_object_name(Processes)`| `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0198', 'SIEM-DE-None-XX-Remote Registry Key modifications', 'This search monitors for remote modifications to registry keys.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Defense Evasion', 'None', '{}', '{}', '| tstats `summariesonly` count values(Registry.registry_key_name) as registry_key_name values(Registry.registry_path) as registry_path min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Registry where  Registry.registry_path="\\\\*"  by Registry.dest , Registry.status, Registry.user | `ctime(lastTime)` | `ctime(firstTime)` | `drop_dm_object_name(Registry)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0199', 'Fake Windows Processes', 'This example finds processes normally run from Windows\System32 or Windows\SysWOW64, running from some other location. This can indicate a malicious process trying to hide as a legitimate process.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0200', 'SIEM-E-None-XX-Detect S3 access from a new IP', 'This search looks at S3 bucket-access logs and detects new or previously unseen remote IP addresses that have successfully accessed an S3 bucket.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', 'sourcetype=aws:s3:accesslogs http_status=200  [search sourcetype=aws:s3:accesslogs http_status=200 | stats earliest(_time) as firstTime latest(_time) as lastTime by bucket_name remote_ip | inputlookup append=t previously_seen_S3_access_from_remote_ip.csv | stats min(firstTime) as firstTime, max(lastTime) as lastTime by bucket_name remote_ip | outputlookup previously_seen_S3_access_from_remote_ip.csv | eval newIP=if(firstTime >= relative_time(now(), "-70m@m"), 1, 0) | where newIP=1 | convert ctime(firstTime) ctime(lastTime) | table bucket_name remote_ip]| iplocation remote_ip |rename remote_ip as src_ip | table _time bucket_name src_ip City Country operation request_uri', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS","Web Server"}', '{"Audit System","AWS Cloud"}'),
('DET-0201', 'Unusually Long Command Line', 'Command-lines that are extremely long can be indicative of malicious activity on your hosts.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Processes by Processes.user Processes.dest Processes.process_name Processes.process | `drop_dm_object_name("Processes")` | `ctime(firstTime)`| `ctime(lastTime)`|  eval processlen=len(process) | eventstats stdev(processlen) as stdev, avg(processlen) as avg by dest | stats max(processlen) as maxlen, values(stdev) as stdevperhost, values(avg) as avgperhost by dest, user, process_name, process| eval threshold = 10 | where maxlen > ((threshold*stdevperhost) + avgperhost)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0202', 'SQL Injection with Long URLs', 'This search looks for long URLs that have several SQL commands visible within them.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1190', 'Initial Access', 'Exploit Public-Facing Application', '{}', '{}', '| tstats `summariesonly` count from datamodel=Web where Web.dest_category=web_server AND (Web.url_length > 1024 OR Web.http_user_agent_length > 200) by Web.src Web.dest Web.url Web.url_length Web.http_user_agent | `drop_dm_object_name("Web")` | eval num_sql_cmds=mvcount(split(url, "alter%20table")) + mvcount(split(url, "between")) + mvcount(split(url, "create%20table")) + mvcount(split(url, "create%20database")) + mvcount(split(url, "create%20index")) + mvcount(split(url, "create%20view")) + mvcount(split(url, "delete")) + mvcount(split(url, "drop%20database")) + mvcount(split(url, "drop%20index")) + mvcount(split(url, "drop%20table")) + mvcount(split(url, "exists")) + mvcount(split(url, "exec")) + mvcount(split(url, "group%20by")) + mvcount(split(url, "having")) + mvcount(split(url, "insert%20into")) + mvcount(split(url, "inner%20join")) + mvcount(split(url, "left%20join")) + mvcount(split(url, "right%20join")) + mvcount(split(url, "full%20join")) + mvcount(split(url, "select")) + mvcount(split(url, "distinct")) + mvcount(split(url, "select%20top")) + mvcount(split(url, "union")) + mvcount(split(url, "xp_cmdshell")) - 24 | where num_sql_cmds > 3', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0203', 'High or Critical Priority Individual Logging into Infected Machine', 'Detects users with a high or critical priority logging into a malware infected machine', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Anti-Virus / Anti-Malware"}', '{"Identity Provider","Active Directory","Antivirus"}'),
('DET-0204', 'AWS New API Call Per Peer Group', 'Looks for users that are using AWS APIs that neither they, nor their team has ever used before.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0205', 'Suspicious Privilege Escalation', 'Detects suspicious privilege escalation by correlating login and privilege escalation events.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0206', 'Prohibited Software On Endpoint', 'This search looks for applications on the endpoint that you have marked as prohibited.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1072', 'Execution', 'Third-party Software', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes by Processes.dest Processes.user Processes.process | `ctime(firstTime)`| `ctime(lastTime)` | `drop_dm_object_name(Processes)` | `prohibited_softwares`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0207', 'Monitor Registry Keys for Print Monitors', 'This search looks for registry activity associated with modifications to the registry key <code>HKLM\SYSTEM\CurrentControlSet\Control\Print\Monitors</code>. In this scenario, an attacker can load an arbitrary .dll into the print-monitor registry by giving the full path name to the after.dll. The system will execute the .dll with elevated (SYSTEM) permissions and will persist after reboot.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1060', 'Persistence', 'Registry Run Keys / Startup Folder', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Registry where Registry.action=modified AND Registry.registry_path="*CurrentControlSet\\Control\\Print\\Monitors*" by Registry.dest, Registry.registry_key_name Registry.status Registry.user Registry.registry_path Registry.action | `drop_dm_object_name(Registry)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0208', 'SIEM-E-TA000-XX-Outbreak Detected', 'Alerts when a potential outbreak is observed based on newly infected systems all exhibiting the same infection', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0209', 'Find Unusually Long CLI Commands', 'Oftentimes we''re able to detect malware by looking for unusually long command line strings.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0210', 'Splunk Enterprise Information Disclosure', 'This search allows you to look for evidence of exploitation for CVE-2018-11409, a Splunk Enterprise Information Disclosure Bug.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1072', 'Defense Evasion', 'Third-party Software', '{}', '{}', 'index=_internal sourcetype=splunkd_ui_access server-info | search clientip!=127.0.0.1 uri_path="*raw/services/server/info/server-info" | rename clientip as src_ip, splunk_server as dest | stats earliest(_time) as firstTime, latest(_time) as lastTime, values(uri) as uri, values(useragent) as http_user_agent, values(user) as user by src_ip, dest | convert ctime(firstTime) ctime(lastTime)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Any Splunk Logs"}', '{}'),
('DET-0211', 'High Process Count', 'Alerts when host has a high number of processes. This may be due to an infection or a runaway process.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1035', 'Execution', 'Service Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0212', 'User with Increase in Outgoing Email', 'Both to detect data exfiltration and compromised account, we can analyze users that are sending out dramatically more data than normal. This search looks per source email address for big increases in volume.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0213', 'New RunAs Host / Privileged Account Combination', 'Privilege escalation (either via RunAs or Scheduled Tasks) create Windows Security EventID 4648 events. This search will find new usernames / host combinations, which will track privilege escalation.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1053', 'Privilege Escalation', 'Scheduled Task', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0214', 'SIEM-PE-None-XX-Detect Path Interception By Creation Of program.exe', 'The search is looking for the creation of program.exe in the C: drive.  The creation of this file in that location may be driven by a motive to perform path interception.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Privilege Escalation', 'None', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.user) as user values(Filesystem.dest) as dest values(Filesystem.file_hash) as file_hash values(Filesystem.file_path) as file_path from datamodel=Endpoint.Filesystem where Filesystem.file_path="C:\\program.exe" by Filesystem.file_name | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0215', 'Schtasks scheduling job on remote system', 'This search looks for flags passed to schtasks.exe on the command-line that indicate a job is being scheduled on a remote system.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1053', 'Persistence', 'Scheduled Task', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = schtasks.exe Processes.process="*/create*" Processes.process="* /s *" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0216', 'Unusual Network Activity', 'Detects events that have rare combination of port/application in firewall data.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1024', 'Command and Control', 'Custom Cryptographic Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Network Communication","Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0217', 'Network Change Detected', 'Detects changes to policies of the network protection devices (such as firewall policy changes).', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Configuration Management"}', '{}'),
('DET-0218', 'Basic Brute Force Detection', 'Uses a simple threshold for Windows Security Logs to alert if there are a large number of failed logins, and at least one successful login from the same source.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0219', 'Remote PowerShell Launches', 'It''s unusual for new users to remotely launch PowerShell on another system. This will track the first time per  user + host combination that powershel is remotely started.Alert Volume: Low (for most companies)', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1021', 'Lateral Movement', 'Remote Services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0220', 'New Service Paths for Host', 'New service creations are uncommon for most hosts. This search will look for both new executables and executables running from new paths launched by services.exe.Alert Volume: High', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Persistence', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0221', 'Scheduled tasks used in BadRabbit ransomware', 'This search looks for flags passed to schtasks.exe on the command-line that indicate that task names related to the execution of Bad Rabbit ransomware were created or deleted.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1053', 'Persistence', 'Scheduled Task', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Processes.process) as process  from datamodel=Endpoint.Processes where Processes.process_name=schtasks.exe (Processes.process= "*create*"  OR Processes.process= "*delete*") by Processes.parent_process Processes.process_name Processes.user | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)` | search (process=*rhaegal* OR process=*drogon* OR *viserion_*)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0222', 'Malicious PowerShell Process - Multiple Suspicious Command-Line Arguments', 'This search looks for PowerShell processes started with a base64 encoded command-line passed to it, with parameters to modify the execution policy for the process, and those that prevent the display of an interactive prompt to the user. This combination of command-line options is suspicious because it overrides the default PowerShell execution policy, attempts to hide itself from the user, and passes an encoded script to be run on the command-line.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=powershell.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`| search (process=*-EncodedCommand* OR process=*-enc*) process=*-Exec* AND process=*-NonI*', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0223', 'Excessive DNS Queries', 'Alerts when a host starts sending excessive DNS queries', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1071', 'Command and Control', 'Standard Application Layer Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0224', 'Blacklisted Domain', 'Generates anomalies for traffic that goes to Blacklisted Domains.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1094', 'Command and Control', 'Custom Command and Control Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0225', 'Geographically Improbable Access Detected', 'Alerts on access attempts that are improbable based on time and geography.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0226', 'Increase in # of Hosts Logged into', 'Find users who log into more hosts than they typically do.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1021', 'Lateral Movement', 'Remote Services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0227', 'Unusual USB Activity', 'Generates anomalies for unusual transfers to/from USB devices. It also tracks the first time an account uses a USB and the first time a different type (e.g., vendor) of USB is used in the enterprise.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP","Endpoint Detection and Response"}', '{"Data Loss Prevention","EDR","Endpoint"}'),
('DET-0228', 'Clients Connecting to Multiple DNS Servers', 'This search allows you to identify the endpoints that have connected to more than five DNS servers and made DNS Queries over the time frame of the search.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Command and Control', 'Exfiltration Over Alternative Protocol', '{}', '{}', '| tstats `summariesonly` count, values(DNS.dest) AS dest dc(DNS.dest) as dest_count from datamodel=Network_Resolution where DNS.message_type=QUERY by DNS.src | `drop_dm_object_name("Network_Resolution")` |where dest_count > 5', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0229', 'Windows Event Log Cleared', 'This search looks for Windows events that indicate one of the Windows event logs has been purged.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '((eventtype=wineventlog_security) AND (signature_id=1102 OR signature_id=1100)) OR ((eventtype=wineventlog_system) AND signature_id=104) | stats count min(_time) as firstTime max(_time) as lastTime by signature_id dest user| `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0230', 'Excessive Data Transmission', 'Detects outliers in the timeseries of outgoing bytes transmission by each user, and each device. This detection will occur both normal traffic, VPN traffic, and separately after profiling connections. The profiling connections model only considers connections that behave as file transfers and ignores other type of connections, such as regular web browsing and interactive chat/video connections. Connection profiling aims to reduce False Positives (FP). Note that connection profiling is only available when network events include information about number of packets.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0231', 'External Website Attack', 'Raises anomalies when there are suspicious patterns in incoming web traffic.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1190', 'Initial Access', 'Exploit Public-Facing Application', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0232', 'Increase in Windows Privilege Escalations', 'Privilege escalation (either via RunAs or Scheduled Tasks) create Windows Security EventID 4648 events. This search will baseline per (original, unprivileged) user and then track deviations.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1053', 'Privilege Escalation', 'Scheduled Task', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0233', 'Email files written outside of the Outlook directory', 'The search looks at the change-analysis data model and detects email files created outside the normal Outlook directory.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1114', 'Collection', 'Email Collection', '{}', '{}', '| tstats `summariesonly` count values(Filesystem.file_path) as file_path min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Filesystem where (Filesystem.file_name=*.dll OR Filesystem.file_name=*.ost) Filesystem.file_path != "C:\\Users\\*\\My Documents\\Outlook Files\\*" by Filesystem.action Filesystem.process_id Filesystem.file_name Filesystem.dest | `drop_dm_object_name("Filesystem")` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0234', 'User Finding Project Code Names from Many Departments', 'Find users trying to collect and analyze internal projects from across multiple departments by analyzing their search logs on company wiki software.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0235', 'New Tables Queried by Salesforce.com Peer Group', 'Salesforce.com supports a simplified query language called SOQL. This search detects users who begin querying sensitive tables that have never been contacted by peer group.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Discovery', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0236', 'Download from Internal Server', 'Detects outliers in the timeseries of downloaded bytes from possible internal servers per user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1039', 'Collection', 'Data from Network Shared Drive', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0237', 'Machine Generated Beacon', 'Correlates beaconing activity with global information in the enterprise to identify suspicious beaconing activity.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1094', 'Command and Control', 'Custom Command and Control Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Web Proxy / NGFW"}', '{"Firewall","Network Device","Web Proxy","Next-Gen Firewall"}'),
('DET-0238', 'Emails with Lookalike Domains', 'Emailing from a domain name that is similar to your own is a common phishing technique, such as splunk.com receiving an email from spiunk.com. This search will detect those similar domains.Alert Volume: Very Low', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1192', 'Initial Access', 'Spearphishing Link', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0239', 'Suspicious Java Classes', 'This search looks for suspicious Java classes that are often used to exploit remote command execution in common Java frameworks, such as Apache Struts.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1203', 'Execution', 'Exploitation for Client Execution', '{}', '{}', 'sourcetype="stream:http" http_method=POST http_content_length>1 | regex form_data="(?i)java\.lang\.(?:runtime|processbuilder)" | rename src_ip as src | stats count earliest(_time) as firstTime, latest(_time) as lastTime, values(url) as uri, values(status) as status, values(http_user_agent) as http_user_agent by src, dest | convert ctime(firstTime) ctime(lastTime)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0240', 'Monitor DNS For Brand Abuse', 'This search looks for DNS requests for faux domains similar to the domains that you want to have monitored for abuse.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1328', 'Establish & Maintain Infrastructure', 'Buy domain name', '{}', '{}', '| tstats `summariesonly` values(DNS.answer) as IPs min(_time) as firstTime from datamodel=Network_Resolution by DNS.src, DNS.query | `drop_dm_object_name("DNS")` | `ctime(firstTime)`| `brand_abuse_dns`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0241', 'SIEM-P-None-XX-AWS Network Access Control List Deleted', 'Enforcing network-access controls is one of the defensive mechanisms used by cloud administrators to restrict access to a cloud instance. After the attacker has gained control of the AWS console by compromising an admin account, they can delete a network ACL and gain access to the instance from anywhere. This search will query the CloudTrail logs to detect users deleting network ACLs.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Persistence', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventName=DeleteNetworkAcl|rename userIdentity.arn as arn  | stats count min(_time) as firstTime max(_time) as lastTime values(errorMessage) values(errorCode) values(userAgent) values(userIdentity.*) by src userName arn eventName | `ctime(lastTime)` | `ctime(firstTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0242', 'Connection to New Domain', 'Detects when users browse to domains never before seen in your organization.', 'CRITICAL'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0243', 'Unusual Machine Access', 'Detects rare device accesses in Microsoft Windows logs.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0244', 'Anomalous New Process', 'Alerts when an anomalous number hosts are detected with a new process.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1035', 'Execution', 'Service Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0245', 'Expected Host Not Reporting', 'Discovers hosts that are longer reporting events but should be submitting log events. This rule is used to monitor hosts that you know should be providing a constant stream of logs in order to determine why the host has failed to provide log data.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Any Splunk Logs"}', '{}'),
('DET-0246', 'Sources Sending a High Volume of DNS Traffic', 'A common method of data exfiltration is to send out a huge volume (in bytes) of DNS or ping requests, embedding data into the payload. This is often not logged.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0247', 'Detect Prohibited Applications Spawning cmd.exe', 'This search looks for executions of cmd.exe spawned by a process that is often abused by attackers and that does not typically launch cmd.exe.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.user) as user values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=cmd.exe by Processes.parent_process_name Processes.process_name Processes.dest | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` |search [`prohibited_apps_launching_cmd`]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0248', 'Detect Large Outbound ICMP Packets', 'This search looks for outbound ICMP packets with a packet size larger than 1,000 bytes. Various threat actors have been known to use ICMP as a command and control channel for their attack infrastructure. Large ICMP packets from an endpoint to a remote host may be indicative of this activity.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1095', 'Command and Control', 'Standard Non-Application Layer Protocol', '{}', '{}', '| tstats `summariesonly` count earliest(_time) as earliest latest(_time) as latest values(All_Traffic.action) values(All_Traffic.bytes) from datamodel=Network_Traffic where All_Traffic.action !=blocked All_Traffic.dest_category !=internal (All_Traffic.protocol=icmp OR All_Traffic.transport=icmp) All_Traffic.bytes > 1000 by All_Traffic.src_ip All_Traffic.dest_ip | `drop_dm_object_name("All_Traffic")` | search ( dest_ip!=10.0.0.0/8 AND dest_ip!=172.16.0.0/12 AND dest_ip!=192.168.0.0/16) | convert ctime(earliest) ctime(latest)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0249', 'Geographically Improbable Access Detected for Privileged Accounts', 'Detecting when the same account is logged into twice in a short period of time but from locations very far away, is key to finding account compromise or account credential sharing for your privileged accounts.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Audit Trail","Audit Trail","AWS"}', '{"Identity Provider","Active Directory","Audit System","AWS Cloud"}'),
('DET-0250', 'Suspicious writes to System Volume Information', 'This search detects writes to the ''System Volume Information'' folder by something other than the System process.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1074', 'Collection', 'Data Staged', '{}', '{}', '(sourcetype=XmlWinEventLog:Microsoft-Windows-Sysmon/Operational OR tag=process) EventCode=11 process_id!=4 file_path=*System\ Volume\ Information* | stats count min(_time) as firstTime max(_time) as lastTime by dest, Image, file_path | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0251', 'Ransomware Extensions', 'This example queries your endpoint data to find encrypted files that ransomware will create. You can often even use these extensions to identify the ransomware affecting a given endpoint.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1204', 'Execution', 'User Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0252', 'SIEM-E-TA001-XX-High Volume Email Activity to Non-corporate Domains by User', 'Alerts on high volume email activity by a user to non-corporate domains.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Exfiltration', 'Exfiltration', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0253', 'Brute Force Access Behavior Detected Over One Day', 'Detects an excessive number of failed login attempts, along with a successful attempt, over a one day period (this could indicate a successful brute force attack)', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0254', 'Default Account Activity Detected', 'Discovers use of default accounts (such as admin, administrator, etc.). Default accounts have default passwords and are therefore commonly targeted by attackers using brute force attack tools.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0255', 'Create local admin accounts using net.exe', 'This search looks for the creation of local administrator accounts using net.exe.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.user) as user values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where (Processs.process_name=net.exe OR Processes.process_name=net1.exe) by Processes.process Processes.process_name Processes.dest | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`  | search (process=*localgroup* OR process=*/add* OR process=*user*)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0256', 'High Number of Hosts Not Updating Malware Signatures', 'Alerts when a high number of hosts not updating malware signatures have been discovered.  These hosts should be evaluated to determine why they are not updating their malware signatures.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0257', 'SIEM-E-None-XX-Osquery pack - ColdRoot detection', 'This search looks for ColdRoot events from the osx-attacks osquery pack.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', '| from datamodel Alerts.Alerts | search app=osquery:results (name=pack_osx-attacks_OSX_ColdRoot_RAT_Launchd OR name=pack_osx-attacks_OSX_ColdRoot_RAT_Files) | rename columns.path as path | bucket _time span=30s | stats count(path) by _time, host, user, path', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0258', 'Threat Activity Detected', 'Alerts when any activity matching threat intelligence is detected.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1071', 'Command and Control', 'Standard Application Layer Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email","DNS","Web Proxy / NGFW","Endpoint Detection and Response","Endpoint Detection and Response","Endpoint Detection and Response","Network Communication","Malware Analysis"}', '{"Email Gateway","Mail Server","DNS Server","Web Proxy","Next-Gen Firewall","EDR","Endpoint","Firewall","Network Device"}'),
('DET-0259', 'Host With Multiple Infections', 'Alerts when a host with multiple infections is discovered.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0260', 'Successful Login of Account for Former Employee', 'You shouldn''t see any successful authentication activity on the accounts of former employees. Track this easily in Splunk.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0261', 'SMB Traffic Allowed', 'This use case looks for any SMB traffic allowed through your firewall.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1210', 'Execution', 'Exploitation of Remote Services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0262', 'Hosts receiving high volume of network traffic from email server', 'This search looks for an increase of data transfers from your email server to your clients. This could be indicative of a malicious actor collecting data using your email server.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Collection', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` sum(All_Traffic.bytes_in) as bytes_in from datamodel=Network_Traffic where All_Traffic.dest_category=email_server by All_Traffic.src_ip _time span=1d | `drop_dm_object_name("All_Traffic")` | eventstats avg(bytes_in) as avg_bytes_in stdev(bytes_in) as stdev_bytes_in | eventstats count as num_data_samples avg(eval(if(_time < relative_time(now(), "@d"), bytes_in, null))) as per_source_avg_bytes_in stdev(eval(if(_time < relative_time(now(), "@d"), bytes_in, null))) as per_source_stdev_bytes_in by src_ip | eval minimum_data_samples = 4, deviation_threshold = 3 | where num_data_samples >= minimum_data_samples AND bytes_in > (avg_bytes_in + (deviation_threshold * stdev_bytes_in)) AND bytes_in > (per_source_avg_bytes_in + (deviation_threshold * per_source_stdev_bytes_in)) AND _time >= relative_time(now(), "@d") | eval num_standard_deviations_away_from_server_average = round(abs(bytes_in - avg_bytes_in) / stdev_bytes_in, 2), num_standard_deviations_away_from_client_average = round(abs(bytes_in - per_source_avg_bytes_in) / per_source_stdev_bytes_in, 2) | table src_ip, _time, bytes_in, avg_bytes_in, per_source_avg_bytes_in, num_standard_deviations_away_from_server_average, num_standard_deviations_away_from_client_average', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0263', 'Remote Desktop Process Running On System', 'This search looks for the remote desktop process mstsc.exe running on systems upon which it doesn''t typically run. This is accomplished by filtering out all systems that are noted in the <code>common_rdp_source category</code> in the Assets and Identity framework.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1076', 'Lateral Movement', 'Remote Desktop Protocol', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process=mstsc.exe AND Processes.dest_category!=common_rdp_source by Processes.dest Processes.user Processes.process | `ctime(firstTime)`| `ctime(lastTime)` | `drop_dm_object_name(Processes)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0264', 'Sources Sending Many DNS Requests', 'A common method for Data Exfiltration is to send out many DNS or Ping requests, embedding data into the payload. This is often not logged.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0265', 'SIEM-P-None-XX-Detect Spike in Network ACL Activity', 'This search will detect users creating spikes in API activity related to network access-control lists (ACLs)in your AWS environment.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Persistence', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail `NetworkACLEvents` [search sourcetype=aws:cloudtrail `NetworkACLEvents` | spath output=arn path=userIdentity.arn | stats count as apiCalls by arn | inputlookup network_acl_activity_baseline append=t | fields - latestCount | stats values(*) as * by arn | rename apiCalls as latestCount | eval newAvgApiCalls=avgApiCalls + (latestCount-avgApiCalls)/720 | eval newStdevApiCalls=sqrt(((pow(stdevApiCalls, 2)*719 + (latestCount-newAvgApiCalls)*(latestCount-avgApiCalls))/720)) | eval avgApiCalls=coalesce(newAvgApiCalls, avgApiCalls), stdevApiCalls=coalesce(newStdevApiCalls, stdevApiCalls), numDataPoints=if(isnull(latestCount), numDataPoints, numDataPoints+1) | table arn, latestCount, numDataPoints, avgApiCalls, stdevApiCalls | outputlookup network_acl_activity_baseline | eval dataPointThreshold = 15, deviationThreshold = 3 | eval isSpike=if((latestCount > avgApiCalls+deviationThreshold*stdevApiCalls) AND numDataPoints > dataPointThreshold, 1, 0) | where isSpike=1 | rename arn as userIdentity.arn | table userIdentity.arn] | spath output=user userIdentity.arn | stats values(eventName) as eventNames, count as numberOfApiCalls, dc(eventName) as uniqueApisCalled by user', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0266', 'Script Execution via WMI', 'This search looks for scripts launched via WMI.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Processes where Processes.process_name = "scrcons.exe" by Processes.user Processes.dest Processes.process_name  | `drop_dm_object_name("Processes")` | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0267', 'Unusual Geolocation of Communication Destination', 'Detects network events with rare destination IP geolocation.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1071', 'Command and Control', 'Standard Application Layer Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0268', 'WMI Permanent Event Subscription - Sysmon', 'This search looks for the creation of WMI permanent event subscriptions.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', 'sourcetype="XmlWinEventLog:Microsoft-Windows-Sysmon/Operational" EventCode=21 | rename host as dest | table _time, dest, user, Operation, EventType, Query, Consumer, Filter', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0269', 'Email servers sending high volume traffic to hosts', 'This search looks for an increase of data transfers from your email server to your clients. This could be indicative of a malicious actor collecting data using your email server.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1114', 'Collection', 'Email Collection', '{}', '{}', '| tstats `summariesonly` sum(All_Traffic.bytes_out) as bytes_out from datamodel=Network_Traffic where All_Traffic.src_category=email_server by All_Traffic.dest_ip _time span=1d | `drop_dm_object_name("All_Traffic")` | eventstats avg(bytes_out) as avg_bytes_out stdev(bytes_out) as stdev_bytes_out | eventstats count as num_data_samples avg(eval(if(_time < relative_time(now(), "@d"), bytes_out, null))) as per_source_avg_bytes_out stdev(eval(if(_time < relative_time(now(), "@d"), bytes_out, null))) as per_source_stdev_bytes_out by dest_ip | eval minimum_data_samples = 4, deviation_threshold = 3 | where num_data_samples >= minimum_data_samples AND bytes_out > (avg_bytes_out + (deviation_threshold * stdev_bytes_out)) AND bytes_out > (per_source_avg_bytes_out + (deviation_threshold * per_source_stdev_bytes_out)) AND _time >= relative_time(now(), "@d") | eval num_standard_deviations_away_from_server_average = round(abs(bytes_out - avg_bytes_out) / stdev_bytes_out, 2), num_standard_deviations_away_from_client_average = round(abs(bytes_out - per_source_avg_bytes_out) / per_source_stdev_bytes_out, 2) | table dest_ip, _time, bytes_out, avg_bytes_out, per_source_avg_bytes_out, num_standard_deviations_away_from_server_average, num_standard_deviations_away_from_client_average', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0270', 'Reg.exe Manipulating Windows Services Registry Keys', 'The search looks for reg.exe modifying registry keys that define Windows services and their configurations.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1050', 'Persistence', 'New Service', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Processes.process_name) as process_name values(Processes.parent_process_name) as parent_process_name FROM datamodel=Endpoint.Processes where Processes.process_name = reg.exe by Processes.process_id Processes.dest | `drop_dm_object_name("Processes")` | `ctime(firstTime)` | `ctime(lastTime)` | join [| tstats `summariesonly` values(Registry.registry_path) as registry_path count  FROM datamodel=Endpoint.Registry where Registry.registry_path="*\\services\\*" by Registry.process_id Registry.dest | `drop_dm_object_name("Registry")` | table process_id dest registry_path]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0271', 'First Time USB Usage', 'Find systems the first time they generate Windows Event ID 20001, which for some customers occurs when a USB drive is plugged in.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1091', 'Lateral Movement', 'Replication Through Removable Media', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP","Endpoint Detection and Response"}', '{"Data Loss Prevention","EDR","Endpoint"}'),
('DET-0272', 'Excessive HTTP Failure Responses', 'Alerts when a host generates a lot of HTTP failures in a short span of time', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1190', 'Initial Access', 'Exploit Public-Facing Application', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0273', 'Significant Increase in Interactively Logged On Users', 'Most systems will have a relatively predictable number of interactively logged on users. This search will look for systems that have dramatically more than they typically do, with a per-user baseline.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0274', 'Processes Tapping Keyboard Events', 'This search looks for processes in an MacOS system that is tapping keyboard events in MacOS, and essentially monitoring all keystrokes made by a user. This is a common technique used by RATs to log keystrokes from a victim, although it can also be used by legitimate processes like Siri to react on human input', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1056', 'Credential Access', 'Input Capture', '{}', '{}', '| from datamodel Alerts.Alerts | search app=osquery:results name=pack_osx-attacks_Keyboard_Event_Taps | rename columns.cmdline as cmd, columns.name as process_name, columns.pid as process_id| dedup host,process_name | table host,process_name, cmd, process_id', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0275', 'Unusual Child Process for spoolsv.exe or connhost.exe', 'In late August 2018, a new Windows Zero Day was announced via Twitter, and the only apparent defense is to detect unusual child processes from spoolsv.exe or connhost.exe. SSE already detected the POC, but this specifically looks for any potential detection.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1068', 'Privilege Escalation', 'Exploitation for Privilege Escalation', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0276', 'Potential Webshell Activity', 'Detects web shell activity by looking at accesses to internal Web servers (by external IPs only).', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1100', 'Persistence', 'Web Shell', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0277', 'Familiar Filename Launched with New Path on Host', 'Processes are typically launched from the same path. When those paths change, it can be a malicious process masquerading as a valid one, to hide in task manager. (https://car.mitre.org/wiki/CAR-2013-05-004">MITRE CAR Reference)Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0278', 'System Processes Run From Unexpected Locations', 'This search looks for system processes that normally run out of C:\Windows\System32\ or C:\Windows\SysWOW64 that are not run from that location.  This can indicate a malicious process that is trying to hide as a legitimate process.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Processes where Processes.process_path !="C:\\Windows\\System32*" Processes.process_path !="C:\\Windows\\SysWOW64*" by Processes.user Processes.dest Processes.process_name Processes.process_path Processes.process_id | `drop_dm_object_name("Processes")` | `ctime(firstTime)`| `ctime(lastTime)`| `isWindowsSystemFile`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0279', 'SIEM-E-None-XX-Detect Spike in blocked Outbound Traffic from your AWS', 'This search will detect spike in blocked outbound network connections originating from within your AWS environment.  It will also update the cache file that factors in the latest data.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Exfiltration', 'None', '{}', '{}', 'sourcetype=aws:cloudwatchlogs:vpcflow action=blocked (src_ip=10.0.0.0/8 OR src_ip=172.16.0.0/12 OR src_ip=192.168.0.0/16) ( dest_ip!=10.0.0.0/8 AND dest_ip!=172.16.0.0/12 AND dest_ip!=192.168.0.0/16)  [search  sourcetype=aws:cloudwatchlogs:vpcflow action=blocked (src_ip=10.0.0.0/8 OR src_ip=172.16.0.0/12 OR src_ip=192.168.0.0/16) ( dest_ip!=10.0.0.0/8 AND dest_ip!=172.16.0.0/12 AND dest_ip!=192.168.0.0/16)  | stats count as numberOfBlockedConnections by src_ip | inputlookup baseline_blocked_outbound_connections append=t | fields - latestCount | stats values(*) as * by src_ip | rename numberOfBlockedConnections as latestCount | eval newAvgBlockedConnections=avgBlockedConnections + (latestCount-avgBlockedConnections)/720 | eval newStdevBlockedConnections=sqrt(((pow(stdevBlockedConnections, 2)*719 + (latestCount-newAvgBlockedConnections)*(latestCount-avgBlockedConnections))/720)) | eval avgBlockedConnections=coalesce(newAvgBlockedConnections, avgBlockedConnections), stdevBlockedConnections=coalesce(newStdevBlockedConnections, stdevBlockedConnections), numDataPoints=if(isnull(latestCount), numDataPoints, numDataPoints+1) | table src_ip, latestCount, numDataPoints, avgBlockedConnections, stdevBlockedConnections | outputlookup baseline_blocked_outbound_connections | eval dataPointThreshold = 5, deviationThreshold = 3 | eval isSpike=if((latestCount > avgBlockedConnections+deviationThreshold*stdevBlockedConnections) AND numDataPoints > dataPointThreshold, 1, 0) | where isSpike=1 | table src_ip] | stats values(dest_ip) as "Blocked Destination IPs", values(interface_id) as "resourceId" count as numberOfBlockedConnections, dc(dest_ip) as uniqueDestConnections by src_ip', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0280', 'Multiple Logins', 'Detects outliers in the timeseries of workstation logins per user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0281', 'Anomalous Audit Trail Activity Detected', 'Discovers anomalous activity such as the deletion of or clearing of log files. Attackers oftentimes clear the log files in order to hide their actions, therefore, this may indicate that the system has been compromised.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0282', 'SIEM-CC-TA001-XX-Windows hosts file modification', 'The search looks for modifications to the hosts file on all Windows endpoints across your environment.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Command and Control', 'Command and Control', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Filesystem  by Filesystem.file_name Filesystem.file_path Filesystem.dest | `ctime(lastTime)` | `ctime(firstTime)` | search Filesystem.file_name=hosts AND Filesystem.file_path=*Windows\\System32\\* | `drop_dm_object_name(Filesystem)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0283', 'Execution of File With Spaces Before Extension', 'This search looks for processes launched from files with at least five spaces in the name before the extension. This is typically done to obfuscate the file extension by pushing it outside of the default view.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1042', 'Execution', 'Change Default File Association', '{}', '{}', '| tstats `summariesonly` count values(Processes.process_path) as process_path min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process = "*     .*" by Processes.dest Processes.user Processes.process Processes.process_name | `ctime(firstTime)`| `ctime(lastTime)` | `drop_dm_object_name(Processes)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0284', 'Common Ransomware Extensions', 'The search looks for file modifications with extensions commonly used by Ransomware', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1074', 'Collection', 'Data Staged', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.user) as user values(Filesystem.dest) as dest values(Filesystem.file_path) as file_path from datamodel=Endpoint.Filesystem by Filesystem.file_name | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`| rex field=file_name "(?<file_extension>\.[^\.]+)$" | `ransomware_extensions`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0285', 'Detect Lateral Movement With WMI', 'This use case looks for WMI being used for lateral movement.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1021', 'Lateral Movement', 'Remote Services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0286', 'Web Uploads to Non-corporate Sites by Users', 'Alerts on high volume web uploads by a user to non-corporate domains.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0287', 'Endpoint Uncleaned Malware Detection', 'Detect a system with a malware detection that was not properly cleaned, as they carry a high risk of damage or disclosure of data.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1204', 'Execution', 'User Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0288', 'Protocols passing authentication in cleartext', 'This search looks for cleartext protocols at risk of leaking credentials. Currently, this consists of legacy protocols such as telnet, POP3, IMAP, and non-anonymous FTP sessions. While some of these protocols can be used over SSL, they typically run on different assigned ports in those cases.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1040', 'Credential Access', 'Network Sniffing', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Network_Traffic where All_Traffic.protocol="tcp" AND (All_Traffic.dest_port="23" OR All_Traffic.dest_port="143" OR All_Traffic.dest_port="110" OR (All_Traffic.dest_port="21" AND All_Traffic.user != "anonymous")) groupby All_Traffic.user All_Traffic.src All_Traffic.dest All_Traffic.dest_port | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name("All_Traffic")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0289', 'Protocol or Port Mismatch', 'This search looks for network traffic on common ports where a higher layer protocol does not match the port that is being used. For example, this search should identify cases where protocols other than HTTP are running on TCP port 80. This can be used by attackers to circumvent firewall restrictions, or as an attempt to hide malicious communications over ports and protocols that are typically allowed and not well inspected.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Command and Control', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Network_Traffic where (All_Traffic.app=dns NOT All_Traffic.dest_port=53) OR ((All_Traffic.app=web-browsing OR All_Traffic.app=http) NOT (All_Traffic.dest_port=80 OR All_Traffic.dest_port=8080 OR All_Traffic.dest_port=8000)) OR (All_Traffic.app=ssl NOT (All_Traffic.dest_port=443 OR All_Traffic.dest_port=8443)) OR (All_Traffic.app=smtp NOT All_Traffic.dest_port=25) by All_Traffic.src_ip, All_Traffic.dest_ip, All_Traffic.app, All_Traffic.dest_port |`ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name("All_Traffic")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0290', 'SIEM-E-TA000-XX-New Suspicious Executable Launch for User', 'Some files rarely get used by legitimate activities, such as at.exe. This search will detect those executables being launched, regardless of the circumstance. (https://car.mitre.org/wiki/CAR-2013-05-004">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0291', 'Host With Old Infection Or Potential Re-Infection', 'Alerts when a host with an old infection is discovered (likely a re-infection).', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1204', 'Execution', 'User Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0292', 'SIEM-E-None-XX-Abnormally High AWS Instances Terminated by User', 'This search looks for CloudTrail events where an abnormally high number of instances were successfully terminated by a user in a 10-minute window', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventName=TerminateInstances errorCode=success | bucket span=10m _time | stats count AS instances_terminated by _time userName | eventstats avg(instances_terminated) as total_terminations_avg, stdev(instances_terminated) as total_terminations_stdev | eval threshold_value = 4 | eval isOutlier=if(instances_terminated > total_terminations_avg+(total_terminations_stdev * threshold_value), 1, 0) | search isOutlier=1 AND _time >= relative_time(now(), "-10m@m")| eval num_standard_deviations_away = round(abs(instances_terminated - total_terminations_avg) / total_terminations_stdev, 2) |table _time, userName, instances_terminated, num_standard_deviations_away, total_terminations_avg, total_terminations_stdev', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0293', 'Detect New Local Admin account', 'This search looks for newly created accounts that have been elevated to local administrators.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Defense Evasion', 'Valid Accounts', '{}', '{}', 'eventtype = wineventlog_security signature_id=4720 OR (signature_id=4732 Group_Name= Administrators) | transaction Security_ID maxspan=180m | search signature_id=4720 signature_id=4732 | table _time user dest signature_id Security_ID Group_Name src_user Message', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0294', 'Inactive Account Activity Detected', 'Discovers previously inactive accounts that are now being used. This may be due to an attacker that successfully gained access to an account that was no longer being used.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0295', 'SIEM-E-TA001-XX-New High Risk Event Types for Salesforce.com User', 'Salesforce.com supports a variety of different event types in their event logs. This search detects users who suddenly query event types associated with data exfiltrationAlert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Exfiltration', 'Exfiltration', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0296', 'SIEM-E-TA001-XX-User with Many DLP Events', 'Detect users that have many DLP events in a short period of time.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Exfiltration', 'Exfiltration', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP"}', '{"Data Loss Prevention"}'),
('DET-0297', 'Concurrent Login Attempts Detected', 'Alerts on concurrent access attempts to an app from different hosts. These are good indicators of shared passwords and potential misuse.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0298', 'Prohibited Port Activity Detected', 'Detects the use of ports that are prohibited. Useful for detecting the installation of new software or a successful compromise of a host (such as the presence of a backdoor or a system communicating with a botnet).', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1065', 'Command and Control', 'Uncommonly Used Port', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0299', 'Detect web traffic to dynamic domain providers', 'This search looks for web connections to dynamic DNS providers.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1102', 'Command and Control', 'Web Service', '{}', '{}', '| tstats summariesonly=true allow_old_summaries=true count values(Web.url) as url min(_time) as firstTime from datamodel=Web where Web.status=200 by Web.src Web.dest Web.status | `drop_dm_object_name("Web")` | `ctime(firstTime)` | `dynamic_dns_web_traffic`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0300', 'Anomalous New Service', 'Alerts when an anomalous number hosts are detected with a new service.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1050', 'Privilege Escalation', 'New Service', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0301', 'Scanning Activity', 'Identifies devices correlated to suspicious vertical and horizontal scanning patters.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1046', 'Discovery', 'Network Service Scanning', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0302', 'Disabled Update Service', 'Splunk can detect the status of services, allowing us to find hosts where the Windows Update service is disabled.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0303', 'Risky Events from Privileged Users', 'When something generally risky occurs to your most privileged users, you likely should respond more quickly. Fortunately, this is easy to do.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Ticket Management"}', '{}'),
('DET-0304', 'SMB Traffic Spike', 'This search looks for spikes in the number of Server Message Block (SMB) traffic connections.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Exfiltration', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count from datamodel=Network_Traffic where All_Traffic.dest_port=139 OR All_Traffic.dest_port=445 OR All_Traffic.app=smb by _time span=1h, All_Traffic.src | `drop_dm_object_name("All_Traffic")` | eventstats max(_time) as maxtime | stats count as num_data_samples max(eval(if(_time >= relative_time(maxtime, "-70m@m"), count, null))) as count avg(eval(if(_time<relative_time(maxtime, "-70m@m"), count, null))) as avg stdev(eval(if(_time<relative_time(maxtime, "-70m@m"), count, null))) as stdev by src | eval upperBound=(avg+stdev*2), isOutlier=if(count > upperBound AND num_data_samples >=50, 1, 0) | where isOutlier=1 | table src count', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0305', 'Malicious PowerShell Process With Obfuscation Techniques', 'This search looks for PowerShell processes launched with arguments that have characters indicative of obfuscation on the command-line.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=powershell.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`| eval num_obfuscation = (mvcount(split(process, "`"))-1) + (mvcount(split(process, "^"))-1) | search num_obfuscation > 0', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0306', 'SIEM-CA-None-XX-Detect AWS API Activities From Unapproved Accounts', 'This search looks for successful CloudTrail activity by user accounts that are not listed in the identity table or <code>aws_service_accounts.csv</code>. It returns event names and count, as well as the first and last time a specific user or service is detected, grouped by users.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Credential Access', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail errorCode=success | rename userName as identity | search NOT [| inputlookup identity_lookup_expanded | fields identity] | search NOT [| inputlookup aws_service_accounts | fields identity] | rename identity as user | stats count min(_time) as firstTime max(_time) as lastTime values(eventName) as eventName by user | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0307', 'Period with Unusual Windows Security Event Sequences', 'Correlates the rate of subtle changes in Active Directory behavior for each account. The correlation happens with: (a) each account''s historic profile, and (b) with the activity of other accounts in the enterprise.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0308', 'Brute Force Access Behavior Detected - Against Category', 'Monitor your security controls and prove your GDPR compliance by detecting brute force (or password guessing) attacks on GDPR-tagged systems.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0309', 'Remote Desktop Network Bruteforce', 'This search looks for RDP application network traffic and filters any source/destination pair generating more than twice the standard deviation of the average traffic.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1076', 'Credential Access', 'Remote Desktop Protocol', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Network_Traffic where All_Traffic.app=rdp by All_Traffic.src All_Traffic.dest All_Traffic.dest_port | eventstats stdev(count) AS stdev avg(count) AS avg p50(count) AS p50| where count>(stdev*2) | rename All_Traffic.src AS src All_Traffic.dest AS dest | table firstTime lastTime src dest count avg p50 stdev', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0310', 'SIEM-E-None-XX-Abnormally High AWS Instances Launched by User', 'This search looks for CloudTrail events where a user successfully launches an abnormally high number of instances.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventName=RunInstances errorCode=success | bucket span=10m _time | stats count AS instances_launched by _time userName | eventstats avg(instances_launched) as total_launched_avg, stdev(instances_launched) as total_launched_stdev | eval threshold_value = 4 | eval isOutlier=if(instances_launched > total_launched_avg+(total_launched_stdev * threshold_value), 1, 0) | search isOutlier=1 AND _time >= relative_time(now(), "-10m@m") | eval num_standard_deviations_away = round(abs(instances_launched - total_launched_avg) / total_launched_stdev, 2) | table _time, userName, instances_launched, num_standard_deviations_away, total_launched_avg, total_launched_stdev', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0311', 'Prohibited Service Detected', 'Alerts when a service in the prohibited service list is detected.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1035', 'Execution', 'Service Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0312', 'SIEM-E-None-XX-Detect API activity from users without MFA', 'This search looks for CloudTrail events where a user logged into the AWS account, is making API calls and has not enabled Multi Factor authentication. Multi factor authentication adds a layer of security by forcing the users to type a unique authentication code from an approved authentication device when they access AWS websites or services. AWS Best Practices recommend that you enable MFA for privileged IAM users.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail userIdentity.sessionContext.attributes.mfaAuthenticated=false | search NOT [| inputlookup aws_service_accounts | fields identity | rename identity as user]| stats  count min(_time) as firstTime max(_time) as lastTime values(eventName) as eventName by userIdentity.arn userIdentity.type user | `ctime(firstTime)`  | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0313', 'First Time Accessing an Internal Git Repository Not Viewed by Peers', 'Find users who accessed a git repository for the first time, where their peer group also hasn''t accessed it before.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0314', 'SIEM-CA-None-XX-Detect Spike in AWS API Activity', 'This search will detect users creating spikes of API activity in your AWS environment.  It will also update the cache file that factors in the latest data.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Credential Access', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventType=AwsApiCall [search sourcetype=aws:cloudtrail eventType=AwsApiCall | spath output=arn path=userIdentity.arn | stats count as apiCalls by arn | inputlookup api_call_by_user_baseline append=t | fields - latestCount | stats values(*) as * by arn | rename apiCalls as latestCount | eval newAvgApiCalls=avgApiCalls + (latestCount-avgApiCalls)/720 | eval newStdevApiCalls=sqrt(((pow(stdevApiCalls, 2)*719 + (latestCount-newAvgApiCalls)*(latestCount-avgApiCalls))/720)) | eval avgApiCalls=coalesce(newAvgApiCalls, avgApiCalls), stdevApiCalls=coalesce(newStdevApiCalls, stdevApiCalls), numDataPoints=if(isnull(latestCount), numDataPoints, numDataPoints+1) | table arn, latestCount, numDataPoints, avgApiCalls, stdevApiCalls | outputlookup api_call_by_user_baseline | eval dataPointThreshold = 15, deviationThreshold = 3 | eval isSpike=if((latestCount > avgApiCalls+deviationThreshold*stdevApiCalls) AND numDataPoints > dataPointThreshold, 1, 0) | where isSpike=1 | rename arn as userIdentity.arn | table userIdentity.arn] | spath output=user userIdentity.arn | stats values(eventName) as eventName, count as numberOfApiCalls, dc(eventName) as uniqueApisCalled by user', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0315', 'Authentication Against a New Domain Controller', 'A common indicator for lateral movement is when a user starts logging into new domain controllers.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1021', 'Lateral Movement', 'Remote Services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0316', 'Activity from Expired User Identity - on Category', 'The GDPR requires that only authorized individuals access personal data. Alert when the account of a past employee is used to log into GDPR-tagged systems', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0317', 'Web Servers Executing Suspicious Processes', 'This search looks for suspicious processes on all systems labeled as web servers.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1082', 'Execution', 'System Information Discovery', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.dest_category="web_server" AND (Processes.process="*whoami*" OR Processes.process="*ping*" OR Processes.process="*iptables*" OR Processes.process="*wget*" OR Processes.process="*service*" OR Processes.process="*curl*") by Processes.process Processes.process_name, Processes.dest Processes.user| `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0318', 'Malicious PowerShell Process - Encoded Command', 'This search looks for PowerShell processes that have encoded the script within the command-line. Malware has been seen using this parameter, as it obfuscates the code and makes it relatively easy to pass a script on the command-line.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=powershell.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search process=*-EncodedCommand* OR  process=*-enc*', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0319', 'Concentration of Discovery Tools by Filename', 'It''s uncommon to see many host discovery tools launched on an endpoint, except in very specific situations. This search will identify tools by filename, and look for many launches. (https://car.mitre.org/wiki/CAR-2016-03-001">MITRE CAR Reference)Alert Volume: Low (unless your company specifically does this)', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1087', 'Discovery', 'Account Discovery', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0320', 'Attempt To Set Default PowerShell Execution Policy To Unrestricted', 'This search looks for the execution of reg.exe with parameters that indicate an attempt to set the default PowerShell execution policy on the system to "Unrestricted"', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=reg.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`| search (process=*add*  process=*Software\\Microsoft\\Powershell\\1\\ShellIds\\Microsoft.PowerShell* process=*ExecutionPolicy* process=*Unrestricted*)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0321', 'Unusual VPN Login Geolocation', 'Detects rare authentication locations in VPN data using geolocation.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0322', 'Suspicious Powershell Activity', 'Detects Powershell based attacks', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0323', 'Process Execution via WMI', 'This search looks for processes launched via WMI.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Processes where Processes.process_name = "scrcons.exe" by Processes.user Processes.dest Processes.process_name  | `drop_dm_object_name("Processes")` | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0324', 'Shim Database Installation With Suspicious Parameters', 'This search detects the process execution and arguments required to silently create a shim database.  The sdbinst.exe application is used to install shim database files (.sdb). A shim is a small library which transparently intercepts an API, changes the parameters passed, handles the operation itself, or redirects the operation elsewhere.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1138', 'Persistence', 'Application Shimming', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = sdbinst.exe Processes.process="*-p*" Processes.process="*-q*" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0325', 'Disabling Remote User Account Control', 'The search looks for modifications to registry keys that control the enforcement of Windows User Account Control (UAC).', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1112', 'Defense Evasion', 'Modify Registry', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Registry where Registry.registry_path="*Windows\\CurrentVersion\\Policies\\System\\LocalAccountTokenFilterPolicy" by Registry.dest, Registry.registry_key_name Registry.status Registry.user Registry.registry_path Registry.action | `drop_dm_object_name(Registry)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0326', 'Detect malicious requests to exploit JBoss servers', 'This search is used to detect malicious HTTP requests crafted to exploit jmx-console in JBoss servers. The malicious requests have a long URL length, as the payload is embedded in the URL.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1203', 'Initial Access', 'Exploitation for Client Execution', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Web where (Web.http_method="GET" OR Web.http_method="HEAD") by Web.http_method, Web.url,Web.url_length Web.src, Web.dest | search Web.url="*jmx-console/HtmlAdaptor?action=invokeOpByName&name=jboss.admin*import*" AND Web.url_length > 200 | `drop_dm_object_name("Web")` | `ctime(firstTime)` | `ctime(lastTime)` | table src, dest_ip, http_method, url, firstTime, lastTime', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0327', 'Activity from Expired User Identity', 'Alerts when an event is discovered from a user associated with identity that is now expired (that is, the end date of the identity has been passed).', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0328', 'User Logged into In-Scope System They Should Not Have', 'Follow your GDPR requirement and action your data mapping exercise by tracking employee/vendor/supplier access to systems, to ensure that they are authorized to view the data present on any systems they log into.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Credential Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0329', 'Suspicious Account Lockout', 'Looks for suspicious account lockouts that do not have any associations with password changes, password resets, password expiry within a specific time interval in and around the lockout period.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0330', 'Web Fraud - Password Sharing Across Accounts', 'This search is used to identify user accounts that share a common password.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', 'sourcetype=stream:http http_content_type=text* uri=/magento2/customer/account/loginPost*  | rex field=form_data "login\[username\]=(?<Username>[^&|^$]+)" | rex field=form_data "login\[password\]=(?<Password>[^&|^$]+)" | stats dc(Username) as UniqueUsernames values(Username) as user list(src_ip) as src_ip by Password|where UniqueUsernames>5', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0331', 'AWS Instance Modified by Unusual User', 'Detects the first time a user modifies an existing instance.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0332', 'Recurring Infection on Host', 'Looks for the same malware occurring multiple times on the same host.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0333', 'New AD Domain Detected', 'New AD domain names in your normal domain controller logs are a symptom of many Pass the Hash tools. While some of the latest don''t produce these artifacts, this remains a very valuable detection mechanism.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1075', 'Lateral Movement', 'Pass the Hash', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0334', 'Remote Desktop Network Traffic', 'This search looks for network traffic on TCP/3389, the default port used by remote desktop. While remote desktop traffic is not uncommon on a network, it is usually associated with known hosts. This search allows for whitelisting both source and destination hosts to remove them from the output of the search so you can focus on the uncommon uses of remote desktop on your network.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1076', 'Lateral Movement', 'Remote Desktop Protocol', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Network_Traffic where All_Traffic.dest_port=3389 AND All_Traffic.dest_category!=common_rdp_destination AND All_Traffic.src_category!=common_rdp_source by All_Traffic.src All_Traffic.dest All_Traffic.dest_port | `drop_dm_object_name("All_Traffic")` | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0335', 'AWS Instance Created by Unusual User', 'Detects the first time a user creates a new instance.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0336', 'SIEM-E-None-XX-Detect New Open S3 buckets', 'This search looks for CloudTrail events where a user has created an open/public S3 bucket.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail AllUsers eventName=PutBucketAcl | spath output=userIdentityArn path=userIdentity.arn | spath output=bucketName path=requestParameters.bucketName | spath output=aclControlList path=requestParameters.AccessControlPolicy.AccessControlList | spath input=aclControlList output=grantee path=Grant{} | mvexpand grantee | spath input=grantee | search Grantee.URI=*AllUsers | rename userIdentityArn as user| table _time, src,awsRegion Permission, Grantee.URI, bucketName, user', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0337', 'Detect processes used for System Network Configuration Discovery', 'This search looks for fast execution of processes used for system network configuration discovery on the endpoint.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1016', 'Discovery', 'System Network Configuration Discovery', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes by Processes.dest Processes.process_name Processes.user _time | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name(Processes)` | search `system_network_configuration_discovery_tools` | transaction dest maxpause=5m |where eventcount>=5 | table firstTime lastTime dest user process_name process parent_process eventcount', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0338', 'Hosts Where Security Sources Go Quiet', 'A frequent concern of SOCs is that their data feeds will disappear. This search will look on a host-by-host basis for when your security sources stop reporting home.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Any Splunk Logs"}', '{}'),
('DET-0339', 'Suspicious Network Exploration', 'Detects users systematically increasing the number of devices that they access over time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0340', 'Vulnerability Scanner Detected (by targets)', 'Detects a potential vulnerability scanner by detecting devices that have triggered events against a large number of unique targets. Vulnerability scanners generally trigger events against a high number of unique hosts when they are scanning a network for vulnerable hosts.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1046', 'Discovery', 'Network Service Scanning', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"IDS / IPS"}', '{"IDS/IPS"}'),
('DET-0341', 'New Interactive Logon from a Service Account', 'In most environments, service accounts should not log on interactively. This search finds new user/host combinations for accounts starting with "svc_." Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0342', 'Monitor Web Traffic For Brand Abuse', 'This search looks for Web requests to faux domains similar to the one that you want to have monitored for abuse.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1328', 'Establish & Maintain Infrastructure', 'Buy domain name', '{}', '{}', '| tstats `summariesonly` values(Web.url) as urls min(_time) as firstTime from datamodel=Web by Web.src | `drop_dm_object_name("Web")` | `ctime(firstTime)` | `brand_abuse_web`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server","Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0343', 'Abnormally High Number of Endpoint Changes By User', 'Detects an abnormally high number of endpoint changes by user account, as they relate to restarts, audits, filesystem, user, and registry modifications.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1031', 'Persistence', 'Modify Existing Service', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0344', 'Brute Force Access Behavior Detected Over One Day - Against Category', 'Monitor your security controls and prove your GDPR compliance by detecting slow and low brute force (or password guessing) attacks on GDPR-tagged systems that occur gradually over the day.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0345', 'SIEM-E-TA000-XX-Detect Rare Executables', 'This search will return a table of rare processes, the names of the systems running them, and the users who initiated each process.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'Execution', '{}', '{}', '| tstats `summariesonly` count values(Processes.dest) as dest values(Processes.user) as user min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes by Processes.process_name  | rename Processes.process_name as process | rex field=user "(?<user_domain>.*)\\\\(?<user_name>.*)" | `ctime(firstTime)`| `ctime(lastTime)`| search [| tstats count from datamodel=Endpoint.Processes by Processes.process_name | rare Processes.process_name limit=30 | rename Processes.process_name as process| `filter_rare_process_whitelist`| table process ]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0346', 'Excessive Failed Logins', 'Detects excessive number of failed login attempts (this is likely a brute force attack)', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0347', 'Ransomware Note Files', 'Most ransomware leaves a note on the endpoint containing directions for the victim to pay a ransom. This use case looks for these note files.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1204', 'Execution', 'User Execution', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0348', 'Deleting Shadow Copies', 'The vssadmin.exe utility is used to interact with the Volume Shadow Copy Service.  Wmic is an interface to the Windows Management Instrumentation.  This search looks for either of these tools being used to delete shadow copies.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1107', 'Execution', 'File Deletion', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where (Processes.process_name=vssadmin.exe OR Processes.process_name=wmic.exe)  by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search process=*delete* AND process=*shadow*', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0349', 'Detect New Login Attempts to Routers', 'The search queries the authentication logs for assets that are categorized as routers in the ES Assets and Identity Framework, to identify connections that have not been seen before in the last 30 days.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '| tstats `summariesonly` count earliest(_time) as earliest latest(_time) as latest from datamodel=Authentication where Authentication.dest_category=router by Authentication.dest Authentication.user| eval isOutlier=if(earliest >= relative_time(now(), "-30d@d"), 1, 0) | where isOutlier=1| `ctime(earliest)`| `ctime(latest)` | `drop_dm_object_name("Authentication")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0350', 'Suspicious Domain Communication', 'Detects covert and malicious communication patterns in network traffic.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1094', 'Command and Control', 'Custom Command and Control Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0351', 'Detect Outbound SMB Traffic', 'This search looks for outbound SMB connections made by hosts within your network to the Internet. SMB traffic is used for Windows file-sharing activity. One of the techniques often used by attackers involves retrieving the credential hash using an SMB request made to a compromised server controlled by the threat actor.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Credential Access', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count earliest(_time) as earliest latest(_time) as latest values(All_Traffic.action) from datamodel=Network_Traffic where All_Traffic.action !=blocked All_Traffic.dest_category !=internal (All_Traffic.dest_port=139 OR All_Traffic.dest_port=445 OR All_Traffic.app=smb) by All_Traffic.src_ip All_Traffic.dest_ip | `drop_dm_object_name("All_Traffic")` | search ( dest_ip!=10.0.0.0/8 AND dest_ip!=172.16.0.0/12 AND dest_ip!=192.168.0.0/16) | convert ctime(earliest) ctime(latest)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0352', 'Suspicious Box Usage', 'Looks for combinations of actions performed by a Box user or against a Box resource that are suspicious.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1011', 'Exfiltration', 'Exfiltration Over Other Network Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0353', 'Prohibited Process Detected', 'Alerts when a service in the prohibited process list is detected.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1050', 'Privilege Escalation', 'New Service', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0354', 'Host Sending Excessive Email', 'Alerts when an host not designated as an e-mail server sends excessive e-mail to one or more target hosts.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1193', 'Initial Access', 'Spearphishing Attachment', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0355', 'Detect Journal Clearing', 'This use case looks for the fsutil process clearing the update sequence number (USN) change journal.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0356', 'SIEM-E-TA000-XX-Spike in File Writes', 'The search looks for a sharp increase in the number of files written to a particular host', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'Execution', '{}', '{}', '| tstats `summariesonly` count FROM datamodel=Endpoint.Filesystem where Filesystem.action=created by _time span=1h, Filesystem.dest | `drop_dm_object_name(Filesystem)` | eventstats max(_time) as maxtime | stats count as num_data_samples max(eval(if(_time >= relative_time(maxtime, "-1d@d"), count, null))) as "count" avg(eval(if(_time<relative_time(maxtime, "-1d@d"), count,null))) as avg stdev(eval(if(_time<relative_time(maxtime, "-1d@d"), count, null))) as stdev by "dest" | eval upperBound=(avg+stdev*4), isOutlier=if((count > upperBound) AND num_data_samples >=20, 1, 0) | search isOutlier=1', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0357', 'First Time Access to Jump Server for Peer Group', 'Detect a user who is logging into a jump server that neither they nor any of their peers have accessed before.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Lateral Movement', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0358', 'SIEM-CC-TA001-XX-Common Ransomware Notes', 'The search looks for files created with names matching those typically used in ransomware notes that tell the victim how to get their data back.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Command and Control', 'Command and Control', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.user) as user values(Filesystem.dest) as dest values(Filesystem.file_path) as file_path from datamodel=Endpoint.Filesystem by Filesystem.file_name | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`|`ransomware_notes`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0359', 'Unusual Web Browser', 'Detects rare events for user agent string, device, and username in outbound HTTP data.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1071', 'Command and Control', 'Standard Application Layer Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0360', 'Processes with High Entropy Names', 'Some malware will launch processes with randomized filenames.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1027', 'Defense Evasion', 'Obfuscated Files or Information', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0361', 'Concentration of Attacker Tools by Filename', 'It''s uncommon to see attacker tools used in rapid succession on an endpoint. This search will identify tools by filename, and look for multiple executions. (https://car.mitre.org/wiki/CAR-2013-04-002">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1087', 'Discovery', 'Account Discovery', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0362', 'Processes created by netsh', 'This search looks for processes launching netsh.exe to execute various commands via the netsh command-line utility. Netsh.exe is a command-line scripting utility that allows you to, either locally or remotely, display or modify the network configuration of a computer that is currently running. Netsh can be used as a persistence proxy technique to execute a helper .dll when netsh.exe is executed. In this search, we are looking for processes spawned by netsh.exe that are executing commands via the command line.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.parent_process="C:\Windows\System32\netsh.exe" by Processes.parent_process Processes.process_name Processes.user Processes.dest | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0363', 'DNS Query Length With High Standard Deviation', 'This search allows you to identify DNS requests and compute the standard deviation on the length of the names being resolved, then filter on two times the standard deviation to show you those queries that are unusually large for your environment.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Command and Control', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count from datamodel=Network_Resolution by DNS.query DNS.record_type |  `drop_dm_object_name("DNS")` | eval query_length = len(query) | table query query_length record_type count stdev | eventstats stdev(query_length) AS stdev avg(query_length) AS avg p50(query_length) AS p50| where query_length>(stdev*2)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0364', 'SIEM-CA-None-XX-Detect Spike in Security Group Activity', 'This search will detect users creating spikes in API activity related to security groups in your AWS environment.  It will also update the cache file that factors in the latest data.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Credential Access', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail `securityGroupAPIs` [search sourcetype=aws:cloudtrail `securityGroupAPIs` | spath output=arn path=userIdentity.arn | stats count as apiCalls by arn | inputlookup security_group_activity_baseline append=t | fields - latestCount | stats values(*) as * by arn | rename apiCalls as latestCount | eval newAvgApiCalls=avgApiCalls + (latestCount-avgApiCalls)/720 | eval newStdevApiCalls=sqrt(((pow(stdevApiCalls, 2)*719 + (latestCount-newAvgApiCalls)*(latestCount-avgApiCalls))/720)) | eval avgApiCalls=coalesce(newAvgApiCalls, avgApiCalls), stdevApiCalls=coalesce(newStdevApiCalls, stdevApiCalls), numDataPoints=if(isnull(latestCount), numDataPoints, numDataPoints+1) | table arn, latestCount, numDataPoints, avgApiCalls, stdevApiCalls | outputlookup security_group_activity_baseline | eval dataPointThreshold = 15, deviationThreshold = 3 | eval isSpike=if((latestCount > avgApiCalls+deviationThreshold*stdevApiCalls) AND numDataPoints > dataPointThreshold, 1, 0) | where isSpike=1 | rename arn as userIdentity.arn | table userIdentity.arn] | spath output=user userIdentity.arn | stats values(eventName) as eventNames, count as numberOfApiCalls, dc(eventName) as uniqueApisCalled by user', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0365', 'Hosts with Varied and Future Timestamps', 'One technique for foiling correlation searches is to alter the system time. This search will detect this scenario.Alert Volume: Low (and should be fixed)', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1099', 'Defense Evasion', 'Timestomp', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Any Splunk Logs"}', '{}'),
('DET-0366', 'Detection of DNS Tunnels', 'This search is used to detect DNS tunneling, by calculating the sum of the length of DNS queries and DNS answers. The search also filters out potential false positives by filtering out queries made to internal systems and the queries originating from internal DNS, Web, and Email servers. Endpoints using DNS as a method of transmission for data exfiltration, command and control, or evasion of security controls can often be detected by noting an unusually large volume of DNS traffic.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Command and Control', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` dc("DNS.query") as count  from datamodel=Network_Resolution  where nodename=DNS "DNS.message_type"="QUERY" NOT (`cim_corporate_web_domain_search("DNS.query")`) NOT "DNS.query"="*.in-addr.arpa" NOT ("DNS.src_category"="svc_infra_dns" OR "DNS.src_category"="svc_infra_webproxy" OR "DNS.src_category"="svc_infra_email*"   ) by "DNS.src","DNS.query" | rename "DNS.src" as src  "DNS.query" as message | eval length=len(message) | stats sum(length) as length by src | append [ tstats `summariesonly` dc("DNS.answer") as count  from datamodel=Network_Resolution  where nodename=DNS "DNS.message_type"="QUERY" NOT (`cim_corporate_web_domain_search("DNS.query")`) NOT "DNS.query"="*.in-addr.arpa" NOT ("DNS.src_category"="svc_infra_dns" OR "DNS.src_category"="svc_infra_webproxy" OR "DNS.src_category"="svc_infra_email*"   ) by "DNS.src","DNS.answer" | rename "DNS.src" as src  "DNS.answer" as message | eval message=if(message=="unknown","", message) | eval length=len(message) | stats sum(length) as length by src ] | stats sum(length) as length by src | where length > 10000', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0367', 'Concentration of Discovery Tools by SHA1 Hash', 'It''s uncommon to see many discovery tools launched on an endpoint, except in specific situations. This search will identify tools by file hash, and look for several in quick succession. (https://car.mitre.org/wiki/CAR-2016-03-001">MITRE CAR Reference)Alert Volume: Low (unless your company specifically does this)', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1087', 'Discovery', 'Account Discovery', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0368', 'Spike in SMB Traffic', 'This search looks for hosts with an unusually high increase in SMB network connections.Alert Volume: Very Low', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1135', 'Discovery', 'Network Share Discovery', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0369', 'Sc.exe Manipulating Windows Services', 'This search looks for arguments to sc.exe indicating the creation or modification of a Windows service.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1050', 'Persistence', 'New Service', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = sc.exe Processes.process="* create *" Processes.process="* config *" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0370', 'Basic Dynamic DNS Detection', 'Detect outbound communication to Dynamic DNS servers, which are frequently leveraged for command and control by all types of attackers.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1333', 'Command and Control', 'Dynamic DNS', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW","DNS"}', '{"Web Proxy","Next-Gen Firewall","DNS Server"}'),
('DET-0371', 'Account Deleted', 'Detects user and computer account deletion', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit"}', '{}'),
('DET-0372', 'Aggregate Risky Events', 'Detect low and slow activities and complex insider threat patterns by finding users with concentrations of risky activities.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Ticket Management"}', '{}'),
('DET-0373', 'AWS APIs Called More Often Than Usual Per User', 'Builds a per-user baseline for how many API calls is normal, and then alerts for deviations.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1260', 'Technical Information Gathering', 'Determine 3rd party infrastructure services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0374', 'Brute Force Access Behavior Detected', 'Detects excessive number of failed login attempts along with a successful attempt (this could indicate a successful brute force attack)', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0375', 'TOR Traffic', 'This search looks for network traffic identified as The Onion Router (TOR), a benign anonymity network which can be abused for a variety of nefarious purposes.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Command and Control', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Network_Traffic where All_Traffic.app=tor AND All_Traffic.action=allowed by All_Traffic.src_ip All_Traffic.dest_ip All_Traffic.dest_port All_Traffic.action | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name("All_Traffic")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0376', 'SIEM-CA-None-XX-AWS Cross Account Activity From Previously Unseen Account', 'This search looks for AssumeRole events where an IAM role in a different account is requested for the first time.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Credential Access', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventName=AssumeRole | spath output=requestingAccountId path=userIdentity.accountId | spath output=requestedAccountId path=resources{}.accountId | search requestingAccountId=* | where requestingAccountId != requestedAccountId | inputlookup append=t previously_seen_aws_cross_account_activity | multireport [| stats min(eval(coalesce(firstTime, strptime(_time,"%Y-%m-%d %H:%M:%S")))) as firstTime max(eval(coalesce(strptime(_time,"%Y-%m-%d %H:%M:%S"), lastTime))) as lastTime by requestingAccountId, requestedAccountId | outputlookup previously_seen_aws_cross_account_activity | where fact=fiction] [| eventstats min(eval(coalesce(firstTime, strptime(_time,"%Y-%m-%d %H:%M:%S")))) as firstTime, max(eval(coalesce(strptime(_time,"%Y-%m-%d %H:%M:%S"), lastTime))) as lastTime by requestingAccountId, requestedAccountId | where firstTime >= relative_time(now(), "-70m@m") AND isnotnull(_time) | spath output=accessKeyId path=responseElements.credentials.accessKeyId | spath output=requestingARN path=resources{}.ARN | stats values(awsRegion) as awsRegion values(firstTime) as firstTime values(lastTime) as lastTime values(sharedEventID) as sharedEventID, values(requestingARN) as src_user, values(responseElements.assumedRoleUser.arn) as dest_user by _time, requestingAccountId, requestedAccountId, accessKeyId] | table _time, firstTime, lastTime, src_user, requestingAccountId, dest_user, requestedAccountId, awsRegion, accessKeyId, sharedEventID', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0377', 'Common Filename Launched from New Path', 'Simpler malware will hide in plain sight with a filename like explorer.exe, running in the user profile. This detection will look for new paths, for common / expected executables. (https://car.mitre.org/wiki/CAR-2013-05-002">MITRE CAR Reference)Alert Volume: Very Low (for most companies)', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0378', 'Basic Scanning', 'Looks for hosts that reach out to more than 500 hosts, or more than 500 ports in a short period of time, indicating scanning.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1046', 'Discovery', 'Network Service Scanning', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0379', 'Spike in Password Reset Emails', 'Sending password reset emails is a common phishing technique. Protect your users by identifying spikes in the number of suspicious emails entering your environment.Alert Volume: Very Low', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1192', 'Initial Access', 'Spearphishing Link', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0380', 'Non-Privileged Users taking Privileged Actions', 'Detect users who shouldn''t be able admins taking privileged actions.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0381', 'New Parent Process for cmd.exe or regedit.exe', 'cmd.exe and regedit.exe tend to be used in the same ways. New parent processes can be suspicious. (https://car.mitre.org/wiki/CAR-2013-02-003">MITRE CAR Reference)Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0382', 'Malicious Command Line Executions', 'Ransomware and other malware variants often execute long commands using command line arguments. This search performs statistical analysis of these CLI arguments to detect potentially malicious executions.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0383', 'Suspicious wevtutil Usage', 'The wevtutil.exe application is the windows event log utility. This searches for wevtutil.exe with parameters for clearing the application, security, setup, or system event logs.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = wevtutil.exe Processes.process="*cl*" (Processes.process="*System*" OR Processes.process="*Security*" OR Processes.process="*Setup*" OR Processes.process="*Application*") by Processes.process_name Processes.parent_process_name Processes.dest Processes.user| `drop_dm_object_name(Processes)` | `ctime(firstTime)` |`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0384', 'New User Account Created On Multiple Hosts', 'Alerts when numerous new accounts are created for a username accounts multiple hosts.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit","Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0385', 'Registry Keys Used For Persistence', 'The search looks for modifications to registry keys that can be used to launch an application or service at system startup.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1103', 'Persistence', 'AppInit DLLs', '{}', '{}', '| tstats `summariesonly` count values(Registry.registry_key_name) as registry_key_name values(Registry.registry_path) as registry_path min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Registry where (Registry.registry_path=*currentversion\\run* OR Registry.registry_path=*currentVersion\\Windows\\Appinit_Dlls* OR Registry.registry_path=CurrentVersion\\Winlogon\\Shell* OR Registry.registry_path=*CurrentVersion\\Winlogon\\Userinit* OR Registry.registry_path=*CurrentVersion\\Winlogon\\VmApplet* OR Registry.registry_path=*currentversion\\policies\\explorer\\run* OR Registry.registry_path=*currentversion\\runservices* OR Registry.registry_path=*\\CurrentControlSet\\Control\\Lsa\\* OR Registry.registry_path="*Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options*" OR Registry.registry_path=HKLM\\SOFTWARE\\Microsoft\\Netsh\\*) by Registry.dest , Registry.status, Registry.user | `ctime(lastTime)` | `ctime(firstTime)` | `drop_dm_object_name(Registry)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0386', 'Concentration of Attacker Tools by SHA1 Hash', 'It''s uncommon to see attacker tools used in rapid succession on an endpoint. This search will identify tools by file hash, and look for multiple executions. (https://car.mitre.org/wiki/CAR-2013-04-002">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1087', 'Discovery', 'Account Discovery', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0387', 'New Cloud Provider for User', 'Detect a user who is accessing a cloud storage provider they''ve never used before.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0388', 'Identify New User Accounts', 'This detection search will help profile user accounts in your environment by identifying newly created accounts that have been added to your network in the past week.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1136', 'Persistence', 'Create Account', '{}', '{}', '| from datamodel Identity_Management.All_Identities  | eval empStatus=case((now()-startDate)<604800, "Accounts created in last week") | search empStatus="Accounts created in last week"| `ctime(endDate)` | `ctime(startDate)`| table identity empStatus endDate startDate', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit","Windows Security","Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0389', 'Hosts Sending To More Destinations Than Normal', 'This will typically detect scanning activity, along with lateral movement activity.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1018', 'Discovery', 'Remote System Discovery', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0390', 'Unusual AWS Regions', 'Looks for activity in AWS Regions that have not been used before across the organization.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0391', 'Detect Excessive User Account Lockouts', 'This search detects user accounts that have been locked out a relatively high number of times in a short period.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Credential Access', 'Valid Accounts', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Change.All_Changes where nodename=All_Changes.Account_Management All_Changes.result="lockout" by All_Changes.user All_Changes.result |`drop_dm_object_name("All_Changes")` |`drop_dm_object_name("Account_Management")`| `ctime(firstTime)` | `ctime(lastTime)` | search count > 5', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0392', 'Detect Mimikatz Via PowerShell And EventCode 4663', 'This search looks for PowerShell reading lsass memory consistent with credential dumping.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1003', 'Credential Access', 'Credential Dumping', '{}', '{}', 'eventtype = wineventlog_security signature_id=4663 Process_Name=*powershell.exe Object_Name=*lsass.exe Access_Mask=0x10 | stats count min(_time) as firstTime max(_time) as lastTime by dest, Process_Name, Process_ID, Message | rename Process_Name as process | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0393', 'Land Speed Violation', 'Raises anomalies when accounts login over VPN from multiple locations within a short time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0394', 'Execution of File with Multiple Extensions', 'This search looks for processes launched from files that have double extensions in the file name. This is typically done to obscure the "real" file extension and make it appear as though the file being accessed is a data file, as opposed to executable content.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1042', 'Execution', 'Change Default File Association', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process = *.doc.exe OR Processes.process = *.htm.exe OR Processes.process = *.html.exe OR Processes.process = *.txt.exe OR Processes.process = *.pdf.exe OR Processes.process = *.doc.exe by Processes.dest Processes.user Processes.process Processes.parent_process | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name(Processes)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0395', 'Detect Long DNS TXT Record Response', 'This search is used to detect attempts to use DNS tunneling, by calculating the length of responses to DNS TXT queries. Endpoints using DNS as a method of transmission for data exfiltration, command and control, or evasion of security controls can often be detected by noting unusually large volumes of DNS traffic.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Command and Control', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Network_Resolution where DNS.message_type=response AND DNS.record_type=TXT by DNS.src DNS.dest DNS.answer DNS.record_type |  `drop_dm_object_name("DNS")` | eval anslen=len(answer) | search anslen>100 | `ctime(firstTime)` | `ctime(lastTime)` | rename src as "Source IP", dest as "Destination IP", answer as "DNS Answer" anslen as "Answer Length" record_type as "DNS Record Type" firstTime as "First Time" lastTime as "Last Time" count as Count | table "Source IP" "Destination IP" "DNS Answer" "DNS Record Type"  "Answer Length" Count "First Time" "Last Time"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0396', 'Scheduled Task Name Used by Dragonfly Threat Actors', 'This search looks for flags passed to schtasks.exe on the command-line that indicate a task name associated with the Dragonfly threat actor was created or deleted.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1053', 'Execution', 'Scheduled Task', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=schtasks.exe  by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search (process=*delete* OR process=*create*) process=*reset*', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0397', 'SIEM-E-None-XX-Single Letter Process On Endpoint', 'This search looks for process names that consist only of a single letter.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes by Processes.dest, Processes.user, Processes.process, Processes.process_name | `drop_dm_object_name(Processes)` | `ctime(lastTime)` | `ctime(firstTime)` | eval process_name_length = len(process_name), endExe = if(substr(process_name, -4) == ".exe", 1, 0) | search process_name_length=5 AND endExe=1 | table count, firstTime, lastTime, dest, user, process, process_name', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0398', 'SIEM-CA-None-XX-Detect Spike in S3 Bucket deletion', 'This search detects users creating spikes in API activity related to deletion of S3 buckets in your AWS environment. It will also update the cache file that factors in the latest data.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Credential Access', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail eventName=DeleteBucket [search sourcetype=aws:cloudtrail eventName=DeleteBucket | spath output=arn path=userIdentity.arn | stats count as apiCalls by arn | inputlookup s3_deletion_baseline append=t | fields - latestCount | stats values(*) as * by arn | rename apiCalls as latestCount | eval newAvgApiCalls=avgApiCalls + (latestCount-avgApiCalls)/720 | eval newStdevApiCalls=sqrt(((pow(stdevApiCalls, 2)*719 + (latestCount-newAvgApiCalls)*(latestCount-avgApiCalls))/720)) | eval avgApiCalls=coalesce(newAvgApiCalls, avgApiCalls), stdevApiCalls=coalesce(newStdevApiCalls, stdevApiCalls), numDataPoints=if(isnull(latestCount), numDataPoints, numDataPoints+1) | table arn, latestCount, numDataPoints, avgApiCalls, stdevApiCalls | outputlookup s3_deletion_baseline | eval dataPointThreshold = 15, deviationThreshold = 3 | eval isSpike=if((latestCount > avgApiCalls+deviationThreshold*stdevApiCalls) AND numDataPoints > dataPointThreshold, 1, 0) | where isSpike=1 | rename arn as userIdentity.arn | table userIdentity.arn] | spath output=user userIdentity.arn | spath output=bucketName path=requestParameters.bucketName | stats values(bucketName) as bucketName, count as numberOfApiCalls, dc(eventName) as uniqueApisCalled by user', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0399', 'Short Lived Windows Accounts', 'This search detects accounts that were created and deleted in a short time period.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'None', 'Valid Accounts', '{}', '{}', '| tstats `summariesonly` values(All_Changes.result_id) as result_id count min(_time) as firstTime max(_time) as lastTime from datamodel=Change where All_Changes.result_id=4720 OR All_Changes.result_id=4726 by _time span=4h All_Changes.user All_Changes.dest | `ctime(lastTime)` | `ctime(firstTime)` | `drop_dm_object_name("All_Changes")` | search result_id = 4720 result_id=4726 | transaction user maxspan=240m | table firstTime lastTime count user dest result_id', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0400', 'Suspicious IP Address Communication', 'Suspicious IP Address Communication', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1094', 'Command and Control', 'Custom Command and Control Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0401', 'Open Redirect in Splunk Web', 'This search allows you to look for evidence of exploitation for CVE-2016-4859, the Splunk Open Redirect Vulnerability.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1203', 'Execution', 'Exploitation for Client Execution', '{}', '{}', 'index=_internal sourcetype=splunk_web_access return_to="/%09/*"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Any Splunk Logs"}', '{}'),
('DET-0402', 'Suspicious Domain Name', 'Detects algorithmically generated domain names using a machine learning model.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1323', 'Adversary OPSEC', 'Domain Generation Algorithms (DGA)', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS","Web Proxy / NGFW"}', '{"DNS Server","Web Proxy","Next-Gen Firewall"}'),
('DET-0403', 'Flight Risk Printing', 'This search implements two heuristics to look for indications that a user is a flight risk. Many people will print offer letters, drafts of their resume, or related docs on the work environment (for convenience, or because they don''t have a printer at home). Detect when that happens.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit"}', '{}'),
('DET-0404', 'SIEM-E-TA001-XX-New Data Exfil DLP Alerts for User', 'When you first seen an alert from a user who hasn''t generated DLP alerts for data exfiltration before, learn about that.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Exfiltration', 'Exfiltration', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP"}', '{"Data Loss Prevention"}'),
('DET-0405', 'DNS Query Requests Resolved by Unauthorized DNS Servers', 'This search will detect DNS requests resolved by unauthorized DNS servers. Legitimate DNS servers should be identified in the Enterprise Security Assets and Identity Framework.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Exfiltration', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count from datamodel=Network_Resolution where DNS.dest_category != dns_server AND DNS.src_category != dns_server by DNS.src DNS.dest | `drop_dm_object_name("DNS")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0406', 'Substantial Increase In Port Activity', 'Alerts when a statistically significant increase in events on a given port is observed.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1065', 'Command and Control', 'Uncommonly Used Port', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0407', 'Suspicious Data Movement', 'Analyzes different types of data transfers per device and per account, both LAN and WAN, to identify unusual data movements. For example, the model monitors both inter firewall-zones LAN transfers and transfers to different countries and marks transfers that deviate from baseline.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1105', 'Lateral Movement', 'Remote File Copy', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0408', 'Unusual Time of Badge Access', 'Detects badge access at unusual time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1360', 'Test Capabilities', 'Test physical access', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Physical Security"}', '{}'),
('DET-0409', 'Short-lived Account Detected', 'Detects when a account or credential is created and then removed a short time later. This may be an indication of malicious activities.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1136', 'Persistence', 'Create Account', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit","User Activity Audit"}', '{}'),
('DET-0410', 'Completely Inactive Account', 'Discovers accounts that are no longer used. Unused accounts should be disabled and are oftentimes used by attackers to gain unauthorized access.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0411', 'Spike in Exported Records from Salesforce.com', 'For many organizations, Salesforce.com contains the most critical information in their company. This use case tracks the number of records exported per day (and is based on a real set of data collection).Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0412', 'Increase in Source Code (Git) Downloads', 'Find users who have downloaded more files from git than normal.Alert Volume: High', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0413', 'Unusual Activity Time', 'Detects unusual activity time of day, or time of week by a user based on their normal access profile.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0414', 'Detect mshta.exe running scripts in command-line arguments', 'This search looks for the execution of "mshta.exe" with command-line arguments that launch a script. The search will return the first time and last time these command-line arguments were used for these executions, as well as the target system, the user, process "mshta.exe" and its parent process.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=mshta.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`| search (process=*vbscript* OR process=*javascript*)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0415', 'Detect Mimikatz Via PowerShell And EventCode 4703', 'This search looks for PowerShell requesting privileges consistent with credential dumping.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1003', 'Credential Access', 'Credential Dumping', '{}', '{}', 'eventtype=wineventlog_security signature_id=4703 Process_Name=*powershell.exe | rex field=Message "Enabled Privileges:\s+(?<privs>\w+)\s+Disabled Privileges:" | where privs="SeDebugPrivilege" | stats count min(_time) as firstTime max(_time) as lastTime by dest, Process_Name, privs, Process_ID, Message | rename privs as "Enabled Privilege" | rename Process_Name as process |  `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0416', 'RunDLL Loading DLL By Ordinal', 'This search looks for DLLs under %AppData% being loaded by rundll32.exe that are calling the exported function at ordinal 2. Calling exported functions by ordinal is not as common as calling by exported name. There was a bug fixed in IDAPro on 2016-08-08 that would not display functions without names.  Calling functions by ordinal would overcome the lack of name and make it harder for analyst to reverse engineer.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1085', 'Execution', 'Rundll32', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = rundll32.exe Processes.process="*AppData*" Processes.process="*,#2" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0417', 'Malicious PowerShell Process - Execution Policy Bypass', 'This search looks for PowerShell processes started with parameters used to bypass the local execution policy for scripts. These parameters are often observed in attacks leveraging PowerShell scripts as they override the default PowerShell execution policy.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=powershell.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`| search process=* -ex* OR process=* bypass *', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0418', 'Multiple Authentications', 'Detects outliers in the timeseries of service or machine authentication successes per user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0419', 'Detect attackers scanning for vulnerable JBoss servers', 'This search looks for specific GET or HEAD requests to web servers that are indicative of reconnaissance attempts to identify vulnerable JBoss servers. JexBoss is described as the exploit tool of choice for this malicious activity.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1082', 'Discovery', 'System Information Discovery', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Web where (Web.http_method="GET" OR Web.http_method="HEAD") AND (Web.url="*/web-console/ServerInfo.jsp*" OR Web.url="*web-console*" OR Web.url="*jmx-console*" OR Web.url = "*invoker*") by Web.http_method, Web.url, Web.src, Web.dest | `drop_dm_object_name("Web")` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0420', 'First time seen command line argument', 'This search looks for command-line arguments that use a <code>/c</code> parameter to execute a command that has not previously been seen.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1064', 'Execution', 'Scripting', '{}', '{}', '| tstats `summariesonly` min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = cmd.exe Processes.process = "* /c *" by Processes.process Processes.process_name Processes.parent_process_name Processes.dest| `drop_dm_object_name(Processes)`| `ctime(firstTime)` | `ctime(lastTime)` | search [| tstats `summariesonly` earliest(_time) as firstTime latest(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = cmd.exe Processes.process = "* /c *" by Processes.process | `drop_dm_object_name(Processes)` | inputlookup append=t previously_seen_cmd_line_arguments | stats min(firstTime) as firstTime, max(lastTime) as lastTime by process | outputlookup previously_seen_cmd_line_arguments | eval newCmdLineArgument=if(firstTime >= relative_time(now(), "-70m@m"), 1, 0) | where newCmdLineArgument=1 | `ctime(firstTime)` | `ctime(lastTime)` | table process]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0421', 'Registry Keys Used For Privilege Escalation', 'This search looks for modifications to registry keys that can be used to elevate privileges. The registry keys under "Image File Execution Options" are used to intercept calls to an executable and can be used to attach malicious binaries to benign system binaries.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1183', 'Privilege Escalation', 'Image File Execution Options Injection', '{}', '{}', '| tstats `summariesonly` count values(Registry.registry_key_name) as registry_key_name values(Registry.registry_path) as registry_path min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Registry where (Registry.registry_path="*Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options*") by Registry.dest , Registry.status, Registry.user | `ctime(lastTime)` | `ctime(firstTime)` | `drop_dm_object_name(Registry)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0422', 'SIEM-DE-None-XX-EC2 Instance Started In Previously Unseen Region', 'This search looks for CloudTrail events where an instance is started in a particular region in the last one hour and then compares it to a lookup file of previously seen regions where an instance was started', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Defense Evasion', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail earliest=-1h StartInstances  | stats earliest(_time) as earliest latest(_time) as latest by awsRegion| inputlookup append=t previously_seen_aws_regions.csv | stats min(earliest) as earliest max(latest) as latest by awsRegion | outputlookup previously_seen_aws_regions.csv | eval regionStatus=if(earliest >= relative_time(now(), "-1d@d"), "Instance Started in a New Region","Previously Seen Region") | convert ctime(earliest) ctime(latest) | where regionStatus="Instance Started in a New Region"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0423', 'Vulnerability Scanner Detected (by events)', 'Detects a potential vulnerability scanner by detecting devices that have triggered a large number of unique events. Vulnerability scanners generally trigger a high number unique events when scanning a host since each vulnerability check tends to trigger a unique event.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1046', 'Discovery', 'Network Service Scanning', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"IDS / IPS"}', '{"IDS/IPS"}'),
('DET-0424', 'Detection ofLogin attempts using SSH', 'Login attempt/Failure: Detection ofLogin attempts using SSH', 'LOW'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Login attempt/Failure', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Event Name Starts with SSH', 'SIGMA'::query_language, '{"NetScreen FW","Login attempt/Failure"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
